// Package client provides a gRPC client for the repayment_service that
// external services can vendor to call V1 and V2 RPCs without re-implementing
// connection management, retry, and reconnect logic.
//
// Usage:
//
//	c, err := client.NewRepaymentServiceClient("repayment-service:10091")
//	if err != nil { ... }
//	defer c.Close()
//
//	resp, err := c.GetContractByNID(ctx, &pb.GetContractByNIDRequest{
//	    Sys:        &pb.SysReq{TransID: id, RequestorID: "ESB"},
//	    NationalID: "020269992026311",
//	})
package client

import (
	"context"
	"sync"
	"time"

	"repayment_service/pb"

	grpc_retry "github.com/grpc-ecosystem/go-grpc-middleware/retry"
	"go.uber.org/zap"
	"google.golang.org/grpc"
	"google.golang.org/grpc/codes"
	"google.golang.org/grpc/connectivity"
	"google.golang.org/grpc/credentials/insecure"
	"google.golang.org/grpc/keepalive"
	"google.golang.org/grpc/status"
)

type (
	// IClientRepaymentService combines V1 and V2 RPCs behind a single client.
	// Callers see one connection, one lifecycle (Close).
	IClientRepaymentService interface {
		// V1 — keyed by contract number
		GetContractInfo(ctx context.Context, req *pb.GetContractInfoRequest) (*pb.GetContractInfoResponse, error)
		GetEarlyLoans(ctx context.Context, req *pb.GetEarlyLoansRequest) (*pb.GetEarlyLoansResponse, error)
		Payment(ctx context.Context, req *pb.PaymentRequest) (*pb.PaymentResponse, error)

		// V2 — keyed by national ID
		GetContractByNID(ctx context.Context, req *pb.GetContractByNIDRequest) (*pb.GetContractByNIDResponse, error)
		GetEarlyLoansV2(ctx context.Context, req *pb.GetEarlyLoansV2Request) (*pb.GetEarlyLoansV2Response, error)

		Close()
	}

	// ClientRepaymentServiceImpl holds a single gRPC connection shared by the
	// V1 and V2 client stubs. mu guards the connection during reconnect.
	ClientRepaymentServiceImpl struct {
		conn     *grpc.ClientConn
		clientV1 pb.RepaymentServiceAPIClient
		clientV2 pb.RepaymentServiceV2APIClient
		mu       sync.Mutex
		addr     string
	}
)

// NewRepaymentServiceClient creates a new gRPC client with retry and keepalive.
func NewRepaymentServiceClient(grpcAddress string) (IClientRepaymentService, error) {
	conn, err := dial(grpcAddress)
	if err != nil {
		zap.L().Error("Can't connect to gRPC server", zap.String("Error msg", err.Error()))
		return nil, err
	}

	return &ClientRepaymentServiceImpl{
		conn:     conn,
		clientV1: pb.NewRepaymentServiceAPIClient(conn),
		clientV2: pb.NewRepaymentServiceV2APIClient(conn),
		addr:     grpcAddress,
	}, nil
}

// dial builds a gRPC connection with the standard retry and keepalive options
// (3 retries, exponential backoff starting at 100ms; 10s ping with 5s timeout).
func dial(addr string) (*grpc.ClientConn, error) {
	retryOpts := []grpc_retry.CallOption{
		grpc_retry.WithMax(3),
		grpc_retry.WithBackoff(grpc_retry.BackoffExponential(100 * time.Millisecond)),
		grpc_retry.WithCodes(codes.Canceled, codes.Unavailable, codes.DeadlineExceeded),
	}
	return grpc.NewClient(
		addr,
		grpc.WithTransportCredentials(insecure.NewCredentials()),
		grpc.WithKeepaliveParams(keepalive.ClientParameters{
			Time:                10 * time.Second,
			Timeout:             5 * time.Second,
			PermitWithoutStream: true,
		}),
		grpc.WithUnaryInterceptor(grpc_retry.UnaryClientInterceptor(retryOpts...)),
	)
}

// reconnect re-establishes the gRPC connection if it is shutdown or in a
// transient-failure state. Idempotent and safe to call concurrently.
func (c *ClientRepaymentServiceImpl) reconnect() error {
	c.mu.Lock()
	defer c.mu.Unlock()

	if c.conn.GetState() != connectivity.Shutdown && c.conn.GetState() != connectivity.TransientFailure {
		return nil
	}

	zap.L().Info("Reconnecting to gRPC server", zap.String("Address", c.addr))
	c.conn.Close()

	conn, err := dial(c.addr)
	if err != nil {
		zap.L().Error("Reconnect failed", zap.String("Error msg", err.Error()))
		return err
	}

	c.conn = conn
	c.clientV1 = pb.NewRepaymentServiceAPIClient(conn)
	c.clientV2 = pb.NewRepaymentServiceV2APIClient(conn)
	zap.L().Info("Reconnected successfully", zap.String("Address", c.addr))
	return nil
}

// invoke wraps a single RPC call with reconnect-on-Unavailable behavior.
// Generic over request/response types so each public method stays a thin shim.
func invoke[Req any, Resp any](
	c *ClientRepaymentServiceImpl,
	ctx context.Context,
	transID, op string,
	req Req,
	rpc func(context.Context, Req) (Resp, error),
) (Resp, error) {
	var zero Resp
	zap.L().Info("Calling Repayment Service",
		zap.String("Operation", op), zap.String("TransID", transID))

	// Pre-flight reconnect if the connection is already broken.
	if c.conn.GetState() == connectivity.Shutdown || c.conn.GetState() == connectivity.TransientFailure {
		if err := c.reconnect(); err != nil {
			zap.L().Error("Failed to reconnect before request",
				zap.String("Operation", op), zap.String("TransID", transID), zap.String("ErrMsg", err.Error()))
			return zero, err
		}
	}

	resp, err := rpc(ctx, req)
	if err != nil {
		zap.L().Error("RPC failed",
			zap.String("Operation", op), zap.String("TransID", transID), zap.String("ErrMsg", err.Error()))

		// Reconnect and retry once on transport-level errors.
		if st, ok := status.FromError(err); ok && (st.Code() == codes.Unavailable || st.Code() == codes.Canceled) {
			if rcErr := c.reconnect(); rcErr != nil {
				zap.L().Error("Reconnect failed after request error",
					zap.String("Operation", op), zap.String("TransID", transID), zap.String("ErrMsg", rcErr.Error()))
				return zero, err
			}
			resp, err = rpc(ctx, req)
			if err != nil {
				zap.L().Error("RPC failed after reconnect",
					zap.String("Operation", op), zap.String("TransID", transID), zap.String("ErrMsg", err.Error()))
				return zero, err
			}
		} else {
			return zero, err
		}
	}

	zap.L().Info("RPC successful",
		zap.String("Operation", op), zap.String("TransID", transID))
	return resp, nil
}

// ==================== V1 ====================

func (c *ClientRepaymentServiceImpl) GetContractInfo(ctx context.Context, req *pb.GetContractInfoRequest) (*pb.GetContractInfoResponse, error) {
	return invoke(c, ctx, req.GetSys().GetTransID(), "GetContractInfo", req,
		func(ctx context.Context, r *pb.GetContractInfoRequest) (*pb.GetContractInfoResponse, error) {
			return c.clientV1.GetContractInfo(ctx, r)
		})
}

func (c *ClientRepaymentServiceImpl) GetEarlyLoans(ctx context.Context, req *pb.GetEarlyLoansRequest) (*pb.GetEarlyLoansResponse, error) {
	return invoke(c, ctx, req.GetSys().GetTransID(), "GetEarlyLoans", req,
		func(ctx context.Context, r *pb.GetEarlyLoansRequest) (*pb.GetEarlyLoansResponse, error) {
			return c.clientV1.GetEarlyLoans(ctx, r)
		})
}

func (c *ClientRepaymentServiceImpl) Payment(ctx context.Context, req *pb.PaymentRequest) (*pb.PaymentResponse, error) {
	return invoke(c, ctx, req.GetSys().GetTransID(), "Payment", req,
		func(ctx context.Context, r *pb.PaymentRequest) (*pb.PaymentResponse, error) {
			return c.clientV1.Payment(ctx, r)
		})
}

// ==================== V2 ====================

func (c *ClientRepaymentServiceImpl) GetContractByNID(ctx context.Context, req *pb.GetContractByNIDRequest) (*pb.GetContractByNIDResponse, error) {
	return invoke(c, ctx, req.GetSys().GetTransID(), "GetContractByNID", req,
		func(ctx context.Context, r *pb.GetContractByNIDRequest) (*pb.GetContractByNIDResponse, error) {
			return c.clientV2.GetContractByNID(ctx, r)
		})
}

func (c *ClientRepaymentServiceImpl) GetEarlyLoansV2(ctx context.Context, req *pb.GetEarlyLoansV2Request) (*pb.GetEarlyLoansV2Response, error) {
	return invoke(c, ctx, req.GetSys().GetTransID(), "GetEarlyLoansV2", req,
		func(ctx context.Context, r *pb.GetEarlyLoansV2Request) (*pb.GetEarlyLoansV2Response, error) {
			return c.clientV2.GetEarlyLoansV2(ctx, r)
		})
}

// Close closes the underlying gRPC connection. Safe to call multiple times.
func (c *ClientRepaymentServiceImpl) Close() {
	c.mu.Lock()
	defer c.mu.Unlock()
	if c.conn != nil {
		c.conn.Close()
		c.conn = nil
		zap.L().Info("gRPC connection closed", zap.String("Address", c.addr))
	}
}

