package main

import (
	"context"
	"fmt"
	"net"
	"net/http"
	"net/http/pprof"
	"os"
	"strconv"
	"sync/atomic"
	"time"

	// For APM metric.Set
	// Core APM package

	"esb-go-libs/activemq"
	_ "repayment_service/cmd/server/statik"
	"repayment_service/config"
	"repayment_service/internal/adapter"
	"repayment_service/internal/api"
	"repayment_service/internal/common"
	"repayment_service/internal/handler"
	"repayment_service/internal/helper"
	"repayment_service/internal/repository"
	"repayment_service/internal/usecase"
	"repayment_service/pb"

	"esb-go-libs/interceptor"

	auth "github.com/grpc-ecosystem/go-grpc-middleware/v2/interceptors/auth"
	"github.com/grpc-ecosystem/grpc-gateway/v2/runtime"
	"github.com/rakyll/statik/fs"
	apmgrpc "go.elastic.co/apm/module/apmgrpc/v2"
	apmhttp "go.elastic.co/apm/module/apmhttp/v2"
	"go.elastic.co/apm/v2"
	"go.uber.org/fx"
	"go.uber.org/fx/fxevent"
	"go.uber.org/zap"
	"google.golang.org/grpc"
	"google.golang.org/grpc/credentials/insecure"
	"google.golang.org/grpc/keepalive"
	"google.golang.org/protobuf/encoding/protojson"
	"google.golang.org/protobuf/proto"
)

// --- Custom Metrics Definitions ---
var (
	// processedRepaymentsTotal is total request had been processed
	// use atomic operations for safe thread
	processedRepayments_ServiceTotal uint64

	// activeFPSSessions is total active session in FPS service
	activeGrpcAppDomino int64
	activeGrpcCif       int64
)

const HttpCodeHeader = "X-Http-Code"

// --- End Custom Metrics Definitions ---

// gatherCustomMetrics is function APM agent  will call frequently to collect metrics
func gatherCustomMetrics(ctx context.Context, metrics *apm.Metrics) error {
	// add metric for total request had been processed
	// It is a sequence value
	metrics.Add("repayment_service_processed_repayments_total", // name of metric
		[]apm.MetricLabel{{Name: "type", Value: "api"}},               // set label
		float64(atomic.LoadUint64(&processedRepayments_ServiceTotal)), // set current value metric
	)

	metrics.Add("repayment_service_active_grpc_appdomino_sessions",
		[]apm.MetricLabel{{Name: "type", Value: "appdomino_grpc_connection"}},
		float64(atomic.LoadInt64(&activeGrpcAppDomino)),
	)

	metrics.Add("repayment_service_active_grpc_cif_sessions",
		[]apm.MetricLabel{{Name: "type", Value: "cif_grpc_connection"}},
		float64(atomic.LoadInt64(&activeGrpcCif)),
	)
	// we can also add others metric more
	return nil
}

type serverDependencies struct {
	fx.In
	Lifecycle fx.Lifecycle
	Logger    *zap.Logger
	Config    *config.Config
	Mux       *http.ServeMux
	PBS       pb.RepaymentServiceAPIServer
	PBSV2     pb.RepaymentServiceV2APIServer
	SoapV1    *handler.RepaymentServiceV1SoapHandler
	SoapV2    *handler.RepaymentServiceV2SoapHandler
}

func main() {
	// registe function collect metric with Elastic APM default Tracer.
	if tr := apm.DefaultTracer(); tr != nil && tr.Recording() {
		tr.RegisterMetricsGatherer(apm.GatherMetricsFunc(gatherCustomMetrics))
		zap.L().Info("Custom metrics gatherer registered with Elastic APM.")
	}

	fx.New(
		fx.WithLogger(func(log *zap.Logger) fxevent.Logger {
			return &fxevent.ConsoleLogger{W: os.Stderr}
		}),
		helper.Provide(),
		api.Provide(),
		handler.Provide(),
		usecase.Provide(),
		repository.Provide(),
		adapter.Provide(),
		fx.Provide(
			config.Load,
			http.NewServeMux,
			NewHTTPServer,
			NewGRPCServer,
		),

		fx.Invoke(func(*http.Server) {}),
		fx.Invoke(func(*grpc.Server) {}),

		//hook on stop app, disconect connection ActiveMQ
		fx.Invoke(stopConnectionJMS),
	).Run()
}

func NewHTTPServer(deps serverDependencies) *http.Server {
	rmux := runtime.NewServeMux(
		runtime.WithMarshalerOption(runtime.MIMEWildcard, &runtime.JSONPb{
			MarshalOptions: protojson.MarshalOptions{
				EmitDefaultValues: true,
			},
		},
		),
		runtime.WithForwardResponseOption(forwardHttpStatusCd),
		runtime.WithErrorHandler(helper.CustomErrorHandler),
	)
	statik, err := fs.New()
	if err != nil {
		deps.Logger.Fatal("Failed to load static files", zap.Error(err))
	}

	// retryOpts := []grpc_retry.CallOption{
	// 	grpc_retry.WithMax(5),
	// 	grpc_retry.WithBackoff(grpc_retry.BackoffExponential(200 * time.Millisecond)),
	// 	grpc_retry.WithCodes(codes.Canceled, codes.Unavailable, codes.DeadlineExceeded, codes.Internal, codes.Aborted, codes.Unknown),
	// }

	opts := []grpc.DialOption{grpc.WithTransportCredentials(insecure.NewCredentials()),
		grpc.WithChainUnaryInterceptor(
			apmgrpc.NewUnaryClientInterceptor(),
			// grpc_retry.UnaryClientInterceptor(retryOpts...),
		),
		grpc.WithChainStreamInterceptor(apmgrpc.NewStreamClientInterceptor()),
		grpc.WithKeepaliveParams(keepalive.ClientParameters{
			Time:                10 * time.Second,
			Timeout:             20 * time.Second,
			PermitWithoutStream: true,
		}),
	}

	err = pb.RegisterRepaymentServiceAPIHandlerFromEndpoint(context.Background(), rmux, fmt.Sprintf(":%s", deps.Config.Base.GRPC.GRPCAddress), opts)
	if err != nil {
		deps.Logger.Fatal("Failed to register gRPC gateway endpoints", zap.Error(err))
	}

	// Register V2 gateway
	err = pb.RegisterRepaymentServiceV2APIHandlerFromEndpoint(context.Background(), rmux, fmt.Sprintf(":%s", deps.Config.Base.GRPC.GRPCAddress), opts)
	if err != nil {
		deps.Logger.Fatal("Failed to register V2 gRPC gateway endpoints", zap.Error(err))
	}
	deps.Mux.Handle("/repayment-service/swagger-ui/", http.StripPrefix("/repayment-service/swagger-ui/", http.FileServer(statik)))
	// SOAP/XML endpoints (registered before the gRPC-gateway catch-all).
	deps.Mux.Handle("/soap/repayment-service", deps.SoapV1)
	deps.Mux.Handle("/soap/repayment-service-v2", deps.SoapV2)
	// pprof debug endpoints. Index handles the sub-routes (heap, goroutine,
	// allocs, block, mutex, threadcreate). Restrict access at the network
	// layer — never expose this on a public-facing port.
	deps.Mux.HandleFunc("/debug/pprof/", pprof.Index)
	deps.Mux.HandleFunc("/debug/pprof/cmdline", pprof.Cmdline)
	deps.Mux.HandleFunc("/debug/pprof/profile", pprof.Profile)
	deps.Mux.HandleFunc("/debug/pprof/symbol", pprof.Symbol)
	deps.Mux.HandleFunc("/debug/pprof/trace", pprof.Trace)
	deps.Mux.Handle("/", rmux)
	apmHandler := apmhttp.Wrap(helper.CorrelationIDMiddleware(deps.Mux))

	srv := &http.Server{
		Addr:    fmt.Sprintf(":%s", deps.Config.Base.HttpAddress),
		Handler: apmHandler,
	}

	deps.Lifecycle.Append(fx.Hook{
		OnStart: func(ctx context.Context) error {
			deps.Logger.Info("Starting HTTP server", zap.String("addr", srv.Addr))
			go func() {
				if err := srv.ListenAndServe(); err != nil && err != http.ErrServerClosed {
					deps.Logger.Error("HTTP server failed to start", zap.Error(err))
				}
				deps.Logger.Info("Listening HTTP server", zap.String("addr", srv.Addr))
			}()
			return nil
		},
		OnStop: func(ctx context.Context) error {
			deps.Logger.Info("*****HTTP SERVER SHUTDOWN*****")
			return srv.Shutdown(ctx)
		},
	})
	return srv

}

func NewGRPCServer(deps serverDependencies) *grpc.Server {
	//define log using in GRPC server - use zap
	zap.ReplaceGlobals(deps.Logger)
	//define GRPC server options
	grpcsrv := grpc.NewServer(
		grpc.KeepaliveParams(keepalive.ServerParameters{
			MaxConnectionIdle:     time.Duration(deps.Config.Base.GRPC.MaxConnectionIdle) * time.Minute,                    // If a client is idle for 30 min, send a GOAWAY
			MaxConnectionAge:      time.Duration(time.Duration(deps.Config.Base.GRPC.MaxConnectionAge)) * time.Hour,        // If any connection is alive for more than 24 hours, send a GOAWAY
			MaxConnectionAgeGrace: time.Duration(time.Duration(deps.Config.Base.GRPC.MaxConnectionAgeGrace)) * time.Minute, // Allow 5 mins for pending RPCs to complete before forcibly closing connections
			Time:                  time.Duration(time.Duration(deps.Config.Base.GRPC.Time)) * time.Second,                  // Ping the client if it is idle for 30 seconds to ensure the connection is still active
			Timeout:               time.Duration(time.Duration(deps.Config.Base.GRPC.TimeOut)) * time.Second,               // Wait 10 second for the ping ack before assuming the connection is dead
		}),
		grpc.KeepaliveEnforcementPolicy(keepalive.EnforcementPolicy{
			MinTime:             time.Duration(time.Duration(deps.Config.Base.GRPC.MinTime)) * time.Second, // If a client pings more than once every 10 seconds, terminate the connection
			PermitWithoutStream: true,                                                                      // Allow pings even when there are no active streams
		}),
		grpc.ChainUnaryInterceptor(
			interceptor.PanicRecover(),
			helper.CustomValidatorInterceptor(),
			helper.TransIDResponseInterceptor(),
			helper.CorrelationIDInterceptor(),
			auth.UnaryServerInterceptor(nil),
			apmgrpc.NewUnaryServerInterceptor(),
		),
		grpc.StreamInterceptor(helper.StreamInterceptor(deps.Logger)),
	)
	//regist GRPC server
	pb.RegisterRepaymentServiceAPIServer(grpcsrv, deps.PBS)
	pb.RegisterRepaymentServiceV2APIServer(grpcsrv, deps.PBSV2)
	//hook onstart - onstop
	deps.Lifecycle.Append(fx.Hook{
		OnStart: func(ctx context.Context) error {
			listener, err := net.Listen("tcp", fmt.Sprintf(":%s", deps.Config.Base.GRPC.GRPCAddress))
			if err != nil {
				// change to Fatal instead of Panic to exit in casse can not listen
				deps.Logger.Fatal("gRPC server: Can't create listener", zap.Error(err))
			}

			go func() {
				deps.Logger.Info("Starting gRPC server", zap.String("addr", deps.Config.Base.GRPC.GRPCAddress))

				err := grpcsrv.Serve(listener)
				if err != nil && err != grpc.ErrServerStopped {
					// log error when it not server stopped only
					deps.Logger.Error("gRPC server failed to serve", zap.Error(err))
				} else {
					// if error is ErrServerStopped that mean normally stop server
					deps.Logger.Info("gRPC server stopped gracefully.")
				}
			}()

			return nil
		},
		OnStop: func(ctx context.Context) error {
			grpcsrv.GracefulStop()
			deps.Logger.Info("*****GRPC SERVER SHUTDOWN*****")
			return nil
		},
	},
	)
	return grpcsrv
}

// func overwrite metadata grpc-gateway to forward httpstatus code
// to refect proto message, use m protoreflect.ProtoMessage
func forwardHttpStatusCd(ctx context.Context, w http.ResponseWriter, _ proto.Message) error {
	smd, ok := runtime.ServerMetadataFromContext(ctx)
	if !ok {
		return nil
	}

	// Forward TransID to HTTP response header
	if vals := smd.HeaderMD.Get(common.TransIDHeaderKey); len(vals) > 0 {
		w.Header().Set(common.TransIDHeaderKey, vals[0])
	}

	if vals := smd.HeaderMD.Get(HttpCodeHeader); len(vals) > 0 {
		code, err := strconv.Atoi(vals[0])
		if err != nil {
			return err
		}
		w.WriteHeader(code)
	}
	return nil
}

// function invoke onstop to clean resource JMS
func stopConnectionJMS(lc fx.Lifecycle, client *activemq.Client) {
	// Append lifecycle hooks
	lc.Append(fx.Hook{
		OnStop: func(ctx context.Context) (err error) {
			if client == nil {
				zap.L().Warn("JMS Connection not found. Go next On Stop hook")
				return nil
			}
			//try disconnect 3 times
			for range 3 {
				if err = client.Disconnect(); err == nil {
					zap.L().Info("Disconnected to JMS. Clean JMS resource success")
					return nil
				}
				time.Sleep(5 * time.Second)
			}
			// still getting error -> call MustDisconnect()
			if err != nil {
				zap.L().Error("Fail to clean resource: Running MustDisconnect()")
				errMust := client.MustDisconnect()
				if errMust != nil {
					zap.L().Error("Fail to clean resource: Fail to disconnect JMS connection after run MustDisconnect()")
					return nil
				}
			}
			return nil
		},
	})
}

