// Load config with priority: OS env > ConfigMap files > default.
//
// ConfigMap support 2 modes:
//   - configmap.dir: scan dir, load all file *.yaml/*.yml follow alphabet order then merge to config
//   - configmap.path: load only 1 file (fallback if dir does not exist)
func Load() (*Config, error) {
	v := viper.New()
	v.SetConfigType("yaml")
	v.SetEnvKeyReplacer(strings.NewReplacer(".", "__"))
	v.AutomaticEnv()

	// Layer 1: default
	if err := v.ReadConfig(bytes.NewReader(defaultConfig)); err != nil {
		return nil, fmt.Errorf("failed to parse default config: %w", err)
	}

	// keySources tracks which source provided each key's final value
	keySources := make(map[string]string)
	for _, k := range v.AllKeys() {
		keySources[k] = "default"
	}

	// Read configmap dir/path from viper (already merged default + env)
	cmDir := v.GetString("configmap.dir")
	cmPath := v.GetString("configmap.path")

	// Layer 2: ConfigMap files
	var aesKey []byte
	loaded := false

	// load files in dir if dir is set
	if cmDir != "" {
		files, err := findConfigFiles(cmDir)
		if err != nil {
			fmt.Printf("[config] warning: failed to scan configmap dir %s: %v\n", cmDir, err)
		} else if len(files) > 0 {
			for _, f := range files {
				data := readFile(f)
				if data == nil {
					continue
				}
				before := snapshotValues(v)
				if err := v.MergeConfig(bytes.NewReader(data)); err != nil {
					fmt.Printf("[config] warning: failed to merge %s: %v\n", f, err)
					continue
				}
				markChangedKeys(v, before, keySources, f)
				fmt.Printf("[config] loaded configmap file: %s\n", f)
				loaded = true
			}
		}
	}

	// Fallback: single file if dir load failed or not set.
	if !loaded && cmPath != "" {
		if cmData := readFile(cmPath); cmData != nil {
			before := snapshotValues(v)
			if err := v.MergeConfig(bytes.NewReader(cmData)); err != nil {
				return nil, fmt.Errorf("failed to merge configmap: %w", err)
			}
			markChangedKeys(v, before, keySources, cmPath)
			fmt.Printf("[config] loaded configmap file: %s\n", cmPath)
			loaded = true
		}
	}

	// Get aes_key: env > configmap > none
	if k := v.GetString("aes_key"); k != "" {
		aesKey = []byte(k)
	}

	// Unmarshal & decrypt
	cfg := &Config{}
	if err := v.Unmarshal(cfg); err != nil {
		return nil, fmt.Errorf("failed to unmarshal config: %w", err)
	}
	if aesKey != nil {
		if err := util_lib.DecryptSecureFields(reflect.ValueOf(cfg).Elem(), aesKey); err != nil {
			return nil, fmt.Errorf("failed to decrypt secure fields: %w", err)
		}
	}

	// Log config source per key
	logConfigSources(v, keySources)

	return cfg, nil
}

// --- helpers ---

// findConfigFiles find all files from dir, order by alphabet.
func findConfigFiles(dir string) ([]string, error) {
	entries, err := os.ReadDir(dir)
	if err != nil {
		return nil, err
	}
	var files []string
	for _, e := range entries {
		if e.IsDir() {
			continue
		}
		name := e.Name()
		ext := strings.ToLower(filepath.Ext(name))
		if ext == ".yaml" || ext == ".yml" {
			files = append(files, filepath.Join(dir, name))
		}
	}
	sort.Strings(files)
	return files, nil
}

func readFile(path string) []byte {
	data, err := os.ReadFile(path)
	if err != nil || len(data) == 0 {
		return nil
	}
	return data
}

// logConfigSources prints the source of each config key for debugging.
func logConfigSources(v *viper.Viper, keySources map[string]string) {
	fmt.Println("[config] --- Config source per key ---")
	for _, key := range v.AllKeys() {
		// Check if env var exists for this key (highest priority)
		envKey := strings.ToUpper(strings.ReplaceAll(key, ".", "__"))
		if _, exists := os.LookupEnv(envKey); exists {
			fmt.Printf("[config]   %s = env (%s)\n", key, envKey)
			continue
		}

		if src, ok := keySources[key]; ok {
			fmt.Printf("[config]   %s = %s\n", key, src)
		} else {
			fmt.Printf("[config]   %s = unknown\n", key)
		}
	}
	fmt.Println("[config] ✓ Config loaded (priority: env > configmap > default)")
}

// snapshotValues captures current values of all keys in viper.
func snapshotValues(v *viper.Viper) map[string]string {
	snap := make(map[string]string)
	for _, k := range v.AllKeys() {
		snap[k] = fmt.Sprintf("%v", v.Get(k))
	}
	return snap
}

// markChangedKeys compares current viper values with a previous snapshot
// and marks keys that changed with the given source label.
func markChangedKeys(v *viper.Viper, before map[string]string, keySources map[string]string, source string) {
	for _, k := range v.AllKeys() {
		current := fmt.Sprintf("%v", v.Get(k))
		prev, existed := before[k]
		if !existed || current != prev {
			keySources[k] = source
		}
	}
}

