package adapter

import (
	"esb-go-libs/activemq"
	util "esb-go-libs/util"
	poolClient "fec_pool_service/cmd/client"
	"fmt"

	"esb-go-libs/dbadapter"
	"repayment_service/config"
	"repayment_service/internal/adapter/metric"

	"go.uber.org/fx"
	"go.uber.org/zap"
)

func newCfAppDbPoolClient(cfg *config.Config) (poolClient.IClientPoolService, error) {
	cfAppDbGrpcAddress := fmt.Sprintf("%s:%s", cfg.CfAppDbClient.Host, cfg.CfAppDbClient.Port)
	client, err := poolClient.NewPoolServerClient(cfAppDbGrpcAddress)
	if err != nil {
		zap.L().Error("Failed to create CfAppDb grpc client", zap.Error(err))
		return nil, err
	}
	metric.IncrementActiveGrpcCfAppDb()
	return client, nil
}

func newCifDbPoolClient(cfg *config.Config) (poolClient.IClientPoolService, error) {
	cifGrpcAddress := fmt.Sprintf("%s:%s", cfg.CifDbClient.Host, cfg.CifDbClient.Port)
	client, err := poolClient.NewPoolServerClient(cifGrpcAddress)
	if err != nil {
		zap.L().Error("Failed to create CifDb grpc client", zap.Error(err))
		return nil, err
	}
	metric.IncrementActiveGrpcCifDb()
	return client, nil
}

func newJMSClient(cfg *config.Config) *activemq.Client {
	return activemq.NewClient(&activemq.JmsConfig{
		AppName:           "repayment_service",
		BrokerUrl:         cfg.JMSConfig.BrokerUrl,
		Username:          cfg.JMSConfig.Username,
		Password:          cfg.JMSConfig.Password,
		HeartBeatTimeout:  cfg.JMSConfig.HeartBeatTimeout,
		MsgTimeout:        cfg.JMSConfig.MsgTimeout,
		UseTls:            cfg.JMSConfig.UseTls,
		ConnectionTimeout: cfg.JMSConfig.ConnectionTimeout,
		// KeepConnectionElapsedTime: 0,
	})
}

func Provide() fx.Option {
	return fx.Provide(
		fx.Annotate(
			util.NewPbConverter,
		),
		//cfAppDb client
		fx.Annotate(
			newCfAppDbPoolClient,
			fx.ResultTags(`name:"CfAppDbClient"`),
		),
		fx.Annotate(
			dbadapter.NewPoolAdapter,
			fx.ParamTags(``, `name:"CfAppDbClient"`), // first param is util.PbConverter have no tag name, the second one is name will be used in repository
			fx.ResultTags(`name:"CfAppDbAdapter"`),
		),
		//cifDb client
		fx.Annotate(
			newCifDbPoolClient,
			fx.ResultTags(`name:"CifDbClient"`),
		),
		fx.Annotate(
			dbadapter.NewPoolAdapter,
			fx.ParamTags(``, `name:"CifDbClient"`), // first param is util.PbConverter have no tag name, the second one is name will be used in repository
			fx.ResultTags(`name:"CifDbAdapter"`),
		),
		//activeMQ
		newJMSClient,
		activemq.NewSender,
		//w4 repayment http adapter
		NewW4RepaymentAdapter,
	)
}

