package model

import "encoding/xml"

// ==================== W4 Repayment Service Requests ====================

// GetContractInfoByNidRequest is the XML request body when querying by national ID.
type GetContractInfoByNidRequest struct {
	XMLName    xml.Name `xml:"GetContractInfoRequest"`
	NationalID string   `xml:"NationalID"`
}

// GetContractInfoByContractNoRequest is the XML request body when querying by contract number.
type GetContractInfoByContractNoRequest struct {
	XMLName    xml.Name `xml:"GetContractInfoRequest"`
	ContractNo string   `xml:"ContractNo"`
}

// ==================== W4 Repayment Service Response ====================

// EnvelopeW4RepaymentResp is the XML response envelope shared by both endpoints.
type EnvelopeW4RepaymentResp struct {
	XMLName   xml.Name        `xml:"Response"`
	Code      string          `xml:"Code"`
	Message   string          `xml:"Message"`
	Timestamp string          `xml:"Timestamp"`
	RequestId string          `xml:"RequestId"`
	Data      W4RepaymentData `xml:"Data"`
}

// W4RepaymentData holds the list of contract items.
type W4RepaymentData struct {
	ContractItems []W4ContractItem `xml:"ContractItem"`
}

// W4ContractItem represents a single contract returned by the W4 service.
type W4ContractItem struct {
	ContractNo     string `xml:"ContractNo"`
	IDCardNumber   string `xml:"IDCardNumber"`
	CustomerName   string `xml:"CustomerName"`
	CompanyName    string `xml:"CompanyName"`
	AmountOverdue  string `xml:"AmountOverdue"`
	MinAmount      string `xml:"MinAmount"`
	PaymentDueDate string `xml:"PaymentDueDate"`
}

files.internal/adapter/w4_repayment_service_ad:
package adapter

import (
	"bytes"
	"context"
	"encoding/base64"
	"encoding/xml"
	"fmt"
	"io"
	"net/http"
	"repayment_service/config"
	"repayment_service/internal/adapter/model"
	"time"

	"go.elastic.co/apm/v2"
	"go.uber.org/fx"
	"go.uber.org/zap"
)

type (
	IW4RepaymentAdapter interface {
		GetContractInfoByNid(ctx context.Context, transID, nationalID string) (response *model.EnvelopeW4RepaymentResp, err error)
		GetContractInfoByContractNo(ctx context.Context, transID, contractNo string) (response *model.EnvelopeW4RepaymentResp, err error)
	}

	w4RepaymentAdapterImpl struct {
		cfg        *config.Config
		httpClient *http.Client
		url        string // precomputed: BaseURL + ContractInfoPath
		authHeader string // precomputed: "Basic <base64(user:pass)>", empty if no credentials
	}
)

func NewW4RepaymentAdapter(cfg *config.Config, params struct {
	fx.In
}) IW4RepaymentAdapter {
	// Precompute static URL and auth header (config does not change at runtime)
	authHeader := ""
	if cfg.W4Service.Username != "" {
		auth := base64.StdEncoding.EncodeToString([]byte(cfg.W4Service.Username + ":" + cfg.W4Service.Password))
		authHeader = "Basic " + auth
	}

	return &w4RepaymentAdapterImpl{
		cfg:        cfg,
		url:        cfg.W4Service.BaseURL + cfg.W4Service.ContractInfoPath,
		authHeader: authHeader,
		httpClient: &http.Client{
			Timeout: time.Duration(cfg.RequestConfig.ReqTimeout) * time.Second,
			Transport: &http.Transport{
				MaxIdleConns:          30,
				MaxIdleConnsPerHost:   30,
				MaxConnsPerHost:       70,
				IdleConnTimeout:       30 * time.Second,
				TLSHandshakeTimeout:   10 * time.Second,
				ResponseHeaderTimeout: 10 * time.Second,
			},
		},
	}
}

// GetContractInfoByNid queries the W4 service for all contracts of a national ID.
func (a *w4RepaymentAdapterImpl) GetContractInfoByNid(ctx context.Context, transID, nationalID string) (*model.EnvelopeW4RepaymentResp, error) {
	span, ctx := apm.StartSpan(ctx, "repaymentServiceV2.adapter.W4.GetContractInfoByNid", "adapter")
	defer span.End()
	span.Context.SetLabel("TransID", transID)

	reqBody := &model.GetContractInfoByNidRequest{NationalID: nationalID}
	return a.callGetContractInfo(ctx, transID, reqBody, "GetContractInfoByNid", nationalID)
}

// GetContractInfoByContractNo queries the W4 service for a single contract by contract number.
func (a *w4RepaymentAdapterImpl) GetContractInfoByContractNo(ctx context.Context, transID, contractNo string) (*model.EnvelopeW4RepaymentResp, error) {
	span, ctx := apm.StartSpan(ctx, "repaymentService.adapter.W4.GetContractInfoByContractNo", "adapter")
	defer span.End()
	span.Context.SetLabel("TransID", transID)

	reqBody := &model.GetContractInfoByContractNoRequest{ContractNo: "000" + contractNo}
	return a.callGetContractInfo(ctx, transID, reqBody, "GetContractInfoByContractNo", contractNo)
}

// callGetContractInfo marshals the request to XML, POSTs to the W4 contract-info endpoint,
// and unmarshals the XML response. Both endpoints share the same URL and response shape.
func (a *w4RepaymentAdapterImpl) callGetContractInfo(ctx context.Context, transID string, reqBody any, operation, key string) (*model.EnvelopeW4RepaymentResp, error) {
	// Marshal request body to XML
	xmlBody, err := xml.Marshal(reqBody)
	if err != nil {
		zap.L().Error(
			"Failed to marshal W4 request to XML",
			zap.String("TransID", transID),
			zap.String("Operation", operation),
			zap.String("ErrMsg", err.Error()),
		)
		return nil, fmt.Errorf("unable to prepare request to W4/repayment")
	}

	httpReq, err := http.NewRequestWithContext(
		ctx,
		http.MethodPost,
		a.url,
		bytes.NewReader(xmlBody),
	)
	if err != nil {
		zap.L().Error(
			"Failed to create W4 http request",
			zap.String("TransID", transID),
			zap.String("Operation", operation),
			zap.String("ErrMsg", err.Error()),
		)
		return nil, fmt.Errorf("unable to request to W4/repayment")
	}

	httpReq.Header.Set("Content-Type", "application/xml")
	httpReq.Header.Set("Accept", "application/xml")
	httpReq.Header.Set("X-Trans-Id", transID)
	if a.authHeader != "" {
		httpReq.Header.Set("Authorization", a.authHeader)
	}

	zap.L().Debug(
		"Calling W4 repayment service",
		zap.String("TransID", transID),
		zap.String("Operation", operation),
		zap.String("Key", key),
		zap.String("URL", a.url),
	)

	resp, err := a.httpClient.Do(httpReq)
	if err != nil {
		apm.CaptureError(ctx, err).Send()
		zap.L().Error(
			"Failed to call W4 repayment service",
			zap.String("TransID", transID),
			zap.String("Operation", operation),
			zap.String("ErrMsg", err.Error()),
		)
		return nil, fmt.Errorf("unable to request to W4/repayment")
	}
	defer resp.Body.Close()

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		zap.L().Error(
			"Failed to read W4 response body",
			zap.String("TransID", transID),
			zap.String("Operation", operation),
			zap.String("ErrMsg", err.Error()),
		)
		return nil, fmt.Errorf("unable to process response from W4/repayment")
	}

	if resp.StatusCode != http.StatusOK {
		zap.L().Error(
			"W4 service returned non-200 status",
			zap.String("TransID", transID),
			zap.String("Operation", operation),
			zap.String("W4RespStatusCode", resp.Status),
			zap.String("Body", string(body)),
		)
		return nil, fmt.Errorf("W4 service returned status %v", resp.Status)
	}

	var envelope model.EnvelopeW4RepaymentResp
	if err = xml.Unmarshal(body, &envelope); err != nil {
		zap.L().Error(
			"Failed to unmarshal W4 XML response",
			zap.String("TransID", transID),
			zap.String("Operation", operation),
			zap.String("ErrMsg", err.Error()),
		)
		return nil, fmt.Errorf("unable to process response from W4/repayment")
	}

	zap.L().Debug(
		"W4 repayment service responded",
		zap.String("TransID", transID),
		zap.String("Operation", operation),
		zap.String("Code", envelope.Code),
		zap.String("Message", envelope.Message),
		zap.String("W4RequestId", envelope.RequestId),
	)

	return &envelope, nil
}

