// ==================== GetContractInfoByNid ====================

func TestGetContractInfoByNid_Success(t *testing.T) {
	const path = "/w4/operation-maintenance/api/v1/repayment/contract-info"
	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		// verify request method, path, headers, and body
		if r.Method != http.MethodPost {
			t.Errorf("method: want POST, got %s", r.Method)
		}
		if r.URL.Path != path {
			t.Errorf("path: want %s, got %s", path, r.URL.Path)
		}
		if ct := r.Header.Get("Content-Type"); ct != "application/xml" {
			t.Errorf("Content-Type: want application/xml, got %s", ct)
		}
