	span, ctx := apm.StartSpan(ctx, "repaymentService.api.GetContractInfo", "api")
	defer span.End()
	span.Context.SetLabel("TransID", req.Sys.TransID)

	reqDTO := a.v1Converter.GetContractInfoReqFromPb(req)

	zap.L().Info(
		"Receive request",
		zap.Any("RequestRepayment", reqDTO),
		zap.String("TransID", req.Sys.TransID),
		zap.String("ContractNumber", req.ContractNo),
		zap.String("Operation", "GetContractInfo"),
	)

	resDTO, err := a.apiUsecase.GetContractInfo(ctx, reqDTO)
	if err != nil {
		apm.CaptureError(ctx, err).Send()
		zap.L().Error(
			"Failed to get GetContractInfo by contract no",
			zap.String("TransID", req.Sys.TransID),
			zap.String("ContractNo", req.ContractNo),
			zap.String("ErrMsg", err.Error()),
		)

		md := metadata.Pairs(HttpCodeHeader, "500")
		_ = grpc.SetHeader(ctx, md)

		return &repPb.GetContractInfoResponse{
			Sys: &repPb.SysResp{
				TransID:     req.Sys.TransID,
				DateTime:    time.Now().Format(time.RFC3339Nano),
				Code:        util.ConvertStrToInt32(common.ReasonErrorWhenCalled.Code()),
				Description: fmt.Sprintf("%s %s ", common.ReasonErrorWhenCalled.Message(), err.Error()),
			},
		}, nil
	}

	res = a.v1Converter.GetContractInfoRespToPb(resDTO)

	zap.L().Info(
		"Response",
		zap.String("ResultGetContractInfo", fmt.Sprintf("Code: %v, Description: %v", res.Sys.Code, res.Sys.Description)),
		zap.String("TransID", req.Sys.TransID),
		zap.String("ContractNumber", req.ContractNo),
		zap.String("Operation", "GetContractInfo"),
	)

	return res, nil
}

