package common

// ReasonCode represents reason code
type ReasonCode string

// Reason General Error
const (
	ReasonGeneralError            ReasonCode = "-1"
	ReasonDBError                 ReasonCode = "-2"
	ReasonCacheError              ReasonCode = "-3"
	ReasonAdapterError            ReasonCode = "-4"
	ReasonInvalidArgument         ReasonCode = "-6"
	ReasonAdapterTimeout          ReasonCode = "-7"
	ReasonPatternTemplateNotMatch ReasonCode = "-8"
	ReasonActionNotFound          ReasonCode = "-9"

	ReasonDataFound       ReasonCode = "1"
	ReasonErrorWhenCalled ReasonCode = "2"
	ReasonDataNotFound    ReasonCode = "3"
)

var reasonCodeValues = map[string]string{
	"-1": "General Error",
	"-2": "DB Error",
	"-3": "Cache Error",
	"-4": "Adapter Error",
	"-5": "Not Found",
	"-6": "Invalid Argument",
	"-7": "Adapter Timeout",
	"-8": "Pattern of template not match",
	"-9": "Action not found",
	"1":  "DATA FOUND",
	"2":  "ERROR WHEN CALLED: ",
	"3":  "DATA_NOT_FOUND",
}

// Code represents reason code
func (rc ReasonCode) Code() string {
	return string(rc)
}

// Message represents reason message
func (rc ReasonCode) Message() string {
	if value, ok := reasonCodeValues[rc.Code()]; ok {
		return value
	}
	return ""
}

// ParseError represents parse error
func ParseError(err error) ReasonCode {
	return ReasonCode(err.Error())
}

