type (
	GetContractInfoRequestDTO struct {
		Sys        SysReqNormDTO `json:"sys"`
		ContractNo string        `json:"contractNo"`
	}

	GetContractInfoResponseDTO struct {
		Sys                SysRespDTO
		ContractNo         *string  `json:"contractNo,omitempty"`
		IDCardNumber       *string  `json:"idCardNumber,omitempty"`
		CustomerName       *string  `json:"customerName,omitempty"`
		CompanyName        *string  `json:"companyName,omitempty"`
		AmountOverdue      *float64 `json:"amountOverdue,omitempty"`
		InstallmentDueDate *string  `json:"installmentDueDate,omitempty"`
		MinAmount          *float64 `json:"minAmount,omitempty"`
		PaymentDueDate     *string  `json:"paymentDueDate,omitempty"`
	}

	SysReqDTO struct {
		TransID   string `json:"transID"`
		PartnerID string `json:"partnerID"`
		DateTime  string `json:"dateTime"`
		IPAddress string `json:"ipAddress"`
	}
	SysRespDTO struct {
