// func write GetContractInfoRequestDTO to string to write log in case can not marshal
func (g *GetContractInfoRequestDTO) ToString(transID string) string {
	jsonData, err := sonic.Marshal(g)
	if err != nil {
		zap.L().Error(
			"Can not marshal GetContractInfoRequestDTO",
			zap.String("TransID", transID),
			zap.String("Request", fmt.Sprintf("%#v", g)),
		)
	}
	return string(jsonData)
}

