			"Can not marshal GetContractInfoResponseDTO",
			zap.String("TransID", transID),
			zap.String("Request", fmt.Sprintf("%#v", g)),
		)
	}
	return string(jsonData)
}

func (p *PaymentRequestDTO) ToArrayByte(transID string) []byte {
	jsonData, _ := sonic.Marshal(PaymentRequestSendMsgToTopic{
		Sys:                p.Sys,
		TransIDRef:         p.TransIDRef,
		ContractNo:         p.ContractNo,
		IDCardNumber:       p.IDCardNumber,
		CustomerName:       p.CustomerName,
