// Package codec handles SOAP/XML encoding and decoding for the repayment
// service handlers. It decodes inbound SOAP envelopes, maps them to internal
// DTOs, builds SOAP response envelopes from usecase results, and writes
// success / fault responses to the HTTP writer.
package codec

import (
	"encoding/xml"
	"net/http"
	"time"

	"repayment_service/internal/handler/model"

	"go.uber.org/zap"
)

// DecodeV1 unmarshals a SOAP request body into the V1 envelope.
func DecodeV1(body []byte) (*model.EnvelopeReqV1, error) {
	var env model.EnvelopeReqV1
	if err := xml.Unmarshal(body, &env); err != nil {
		return nil, err
	}
	return &env, nil
}

// DecodeV2 unmarshals a SOAP request body into the V2 envelope.
func DecodeV2(body []byte) (*model.EnvelopeReqV2, error) {
	var env model.EnvelopeReqV2
	if err := xml.Unmarshal(body, &env); err != nil {
		return nil, err
	}
	return &env, nil
}

// WriteResponse writes a SOAP envelope (success or operation-shaped error)
// with HTTP 200. The content is the operation's response struct (e.g.
// model.GetContractInfoResp), which carries its own namespaced root element.
func WriteResponse(w http.ResponseWriter, content any) {
	w.Header().Set("Content-Type", "text/xml; charset=utf-8")
	if err := xml.NewEncoder(w).Encode(model.NewEnvelope(content)); err != nil {
		zap.L().Error("Failed to encode SOAP response", zap.String("ErrMsg", err.Error()))
	}
}

// WriteErrorResponse writes the operation-shaped envelope with HTTP 500 so
// load balancers, APM, and alerting flag the request as a server failure
// without having to parse the SOAP body. Use this only for server-side errors
// (e.g. usecase errors). Validation errors keep HTTP 200 since the client is
// at fault, not the server.
func WriteErrorResponse(w http.ResponseWriter, content any) {
	w.Header().Set("Content-Type", "text/xml; charset=utf-8")
	w.WriteHeader(http.StatusInternalServerError)
	if err := xml.NewEncoder(w).Encode(model.NewEnvelope(content)); err != nil {
		zap.L().Error("Failed to encode SOAP error response", zap.String("ErrMsg", err.Error()))
	}
}

// WriteFault writes a SOAP fault envelope with HTTP 500.
func WriteFault(w http.ResponseWriter, transID, code, description string) {
	w.Header().Set("Content-Type", "text/xml; charset=utf-8")
	w.WriteHeader(http.StatusInternalServerError)
	if err := xml.NewEncoder(w).Encode(model.NewFault(transID, code, description)); err != nil {
		zap.L().Error("Failed to encode SOAP Fault", zap.String("ErrMsg", err.Error()), zap.String("TransID", transID))
	}
}

// nowRFC3339 returns the current time formatted with RFC3339Nano (matches the
// format used by usecase responses elsewhere in the codebase).
func nowRFC3339() string {
	return time.Now().Format(time.RFC3339Nano)
}

