		t.Errorf("unexpected NationalID: %s", env.Body.GetContractByNID.NationalID)
	}
}

func TestDecodeV1_InvalidXML(t *testing.T) {
	if _, err := DecodeV1([]byte("not xml")); err == nil {
		t.Fatal("expected error for invalid XML")
	}
}

