package codec

import (
	"math"

	"repayment_service/internal/dto"
	"repayment_service/internal/handler/model"
	pb "repayment_service/pb"
)

// nsV1 is the V1 service target namespace (from RepaymentService.wsdl).
const nsV1 = "http://RepaymentService"

// ==================== GetContractInfo ====================

// GetContractInfoToDTO maps the SOAP V1 GetContractInfo request to its DTO.
func GetContractInfoToDTO(m *model.GetContractInfoReq) *dto.GetContractInfoRequestDTO {
	return &dto.GetContractInfoRequestDTO{
		Sys: dto.SysReqNormDTO{
			TransID:     m.SysRequest.TransID,
			RequestorID: m.SysRequest.PartnerID,
			DateTime:    m.SysRequest.DateTime,
		},
