	}
}

// GetContractInfoToPb builds the pb request used for validation.
func GetContractInfoToPb(m *model.GetContractInfoReq) *pb.GetContractInfoRequest {
	return &pb.GetContractInfoRequest{
		Sys: &pb.SysReq{
			TransID:     m.SysRequest.TransID,
			RequestorID: m.SysRequest.PartnerID,
			DateTime:    m.SysRequest.DateTime,
		},
		ContractNo: m.ContractNo,
	}
}

// BuildGetContractInfoResp builds the SOAP V1 GetContractInfoResponse element.
func BuildGetContractInfoResp(resDTO *dto.GetContractInfoResponseDTO) model.GetContractInfoResp {
	resp := model.GetContractInfoResp{
		NS1: nsV1,
		SysResponse: model.SysRespCode{
			TransID:     resDTO.Sys.TransID,
			DateTime:    resDTO.Sys.DateTime,
			Code:        int32(resDTO.Sys.Code),
			Description: resDTO.Sys.Description,
		},
		ContractNo:         resDTO.ContractNo,
		IDCardNumber:       resDTO.IDCardNumber,
		CustomerName:       resDTO.CustomerName,
		CompanyName:        resDTO.CompanyName,
		InstallmentDueDate: resDTO.InstallmentDueDate,
		PaymentDueDate:     resDTO.PaymentDueDate,
	}
	if resDTO.AmountOverdue != nil {
		v := int64(math.Ceil(*resDTO.AmountOverdue))
		resp.AmountOverdue = &v
	}
	if resDTO.MinAmount != nil {
		v := int64(math.Ceil(*resDTO.MinAmount))
		resp.MinAmount = &v
	}
	return resp
}

// ==================== Payment ====================

