// ==================== GetEarlyLoans ====================

// GetEarlyLoansToDTO maps the SOAP V1 GetEarlyLoans request to its DTO.
func GetEarlyLoansToDTO(m *model.GetEarlyLoansReq) *dto.GetEarlyLoansRequestDTO {
	return &dto.GetEarlyLoansRequestDTO{
		Sys: dto.SysReqNormDTO{
			TransID:     m.SysRequest.TransID,
			RequestorID: m.SysRequest.RequestorID,
			DateTime:    m.SysRequest.DateTime,
		},
		ContractNo: m.ContractNo,
	}
}

// GetEarlyLoansToPb builds the pb request used for validation.
func GetEarlyLoansToPb(m *model.GetEarlyLoansReq) *pb.GetEarlyLoansRequest {
	return &pb.GetEarlyLoansRequest{
		Sys: &pb.SysReq{
			TransID:     m.SysRequest.TransID,
			RequestorID: m.SysRequest.RequestorID,
			DateTime:    m.SysRequest.DateTime,
		},
		ContractNo: m.ContractNo,
	}
}

// BuildGetEarlyLoansResp builds the SOAP V1 GetEarlyLoansResponse element.
func BuildGetEarlyLoansResp(resDTO *dto.GetEarlyLoansResponseDTO) model.GetEarlyLoansResp {
	resp := model.GetEarlyLoansResp{
		NS1: nsV1,
		SysResponse: model.SysRespStatus{
			TransID:     resDTO.Sys.TransID,
			DateTime:    resDTO.Sys.DateTime,
			Status:      int32(resDTO.Sys.Code),
			Description: resDTO.Sys.Description,
		},
	}
	if resDTO.POItem != nil {
		resp.POItem = &model.EarlyLoan{
			PONumber:    resDTO.POItem.PONumber,
			Duedate:     resDTO.POItem.DueDate,
			Money:       resDTO.POItem.Money,
			ContractNum: resDTO.POItem.ContractNum,
			Note:        resDTO.POItem.Note,
		}
	}
	return resp
}

// ==================== Error responses (operation-shaped) ====================
//
// These produce the SAME envelope shape as the corresponding success response
// (so callers can parse one element type per operation), but with the data
// fields omitted and the SysResponse populated with the error code/description.
// Use these for post-routing business errors (validation, usecase failure).
// Pre-routing transport errors (auth, malformed XML, unknown route) still use
// the SOAP Fault envelope via codec.WriteFault.

// BuildGetContractInfoErrorResp returns the V1 GetContractInfo response shape
// with no data fields, only the error SysResponse populated.
func BuildGetContractInfoErrorResp(transID string, code int32, description string) model.GetContractInfoResp {
	return model.GetContractInfoResp{
		NS1: nsV1,
		SysResponse: model.SysRespCode{
			TransID:     transID,
			DateTime:    nowRFC3339(),
			Code:        code,
			Description: description,
		},
	}
}

// BuildPaymentErrorResp returns the V1 Payment response shape with the error
// SysResponse populated.
func BuildPaymentErrorResp(transID string, code int32, description string) model.PaymentResp {
	return model.PaymentResp{
		NS1: nsV1,
		SysResponse: model.SysRespCode{
			TransID:     transID,
			DateTime:    nowRFC3339(),
			Code:        code,
			Description: description,
		},
	}
}

// BuildGetEarlyLoansErrorResp returns the V1 GetEarlyLoans response shape with
// no POItem, only the error SysResponse populated. Note this operation uses
// SysRespStatus (Status field, not Code).
func BuildGetEarlyLoansErrorResp(transID string, status int32, description string) model.GetEarlyLoansResp {
	return model.GetEarlyLoansResp{
		NS1: nsV1,
		SysResponse: model.SysRespStatus{
			TransID:     transID,
			DateTime:    nowRFC3339(),
			Status:      status,
			Description: description,
		},
	}
}

