// BuildGetContractByNIDResp builds the SOAP V2 GetContractbyNIDResponse element.
func BuildGetContractByNIDResp(resDTO *dto.GetContractByNIDResponseDTO) model.GetContractByNIDResp {
	resp := model.GetContractByNIDResp{
		NS1: nsV2,
		SysResponse: model.SysRespStatus{
