		resp.ContractInfo = items
	}
	return resp
}

// ==================== GetEarlyLoansV2 ====================

// GetEarlyLoansV2ToDTO maps the SOAP V2 GetEarlyLoans request to its DTO.
func GetEarlyLoansV2ToDTO(m *model.GetEarlyLoansV2Req) *dto.GetEarlyLoansV2RequestDTO {
	return &dto.GetEarlyLoansV2RequestDTO{
		Sys: dto.SysReqNormDTO{
			TransID:     m.SysRequest.TransID,
			RequestorID: m.SysRequest.RequestorID,
			DateTime:    m.SysRequest.DateTime,
		},
		NationalID: m.NationalID,
	}
}

// GetEarlyLoansV2ToPb builds the pb request used for validation.
func GetEarlyLoansV2ToPb(m *model.GetEarlyLoansV2Req) *pb.GetEarlyLoansV2Request {
	return &pb.GetEarlyLoansV2Request{
		Sys: &pb.SysReq{
			TransID:     m.SysRequest.TransID,
			RequestorID: m.SysRequest.RequestorID,
			DateTime:    m.SysRequest.DateTime,
		},
		NationalID: m.NationalID,
	}
}

// BuildGetEarlyLoansV2Resp builds the SOAP V2 GetEarlyLoansResponse element.
func BuildGetEarlyLoansV2Resp(resDTO *dto.GetEarlyLoansV2ResponseDTO) model.GetEarlyLoansV2Resp {
	resp := model.GetEarlyLoansV2Resp{
		NS1: nsV2,
		SysResponse: model.SysRespStatus{
			TransID:     resDTO.Sys.TransID,
			DateTime:    resDTO.Sys.DateTime,
			Status:      int32(resDTO.Sys.Code),
			Description: resDTO.Sys.Description,
		},
	}
	if len(resDTO.GetEarlyLoansResult) > 0 {
		items := make([]model.EarlyLoan, 0, len(resDTO.GetEarlyLoansResult))
		for _, it := range resDTO.GetEarlyLoansResult {
			items = append(items, model.EarlyLoan{
				PONumber:    it.PONumber,
				Duedate:     it.DueDate,
				Money:       it.Money,
				ContractNum: it.ContractNum,
				Note:        it.Note,
			})
		}
		resp.GetEarlyLoansResult = &model.ArrayOfEarlyLoan{POItem: items}
	}
	return resp
}

// ==================== Error responses (operation-shaped) ====================

// BuildGetContractByNIDErrorResp returns the V2 GetContractbyNID response shape
// with no ContractInfo, only the error SysResponse populated.
func BuildGetContractByNIDErrorResp(transID string, status int32, description string) model.GetContractByNIDResp {
	return model.GetContractByNIDResp{
		NS1: nsV2,
		SysResponse: model.SysRespStatus{
			TransID:     transID,
			DateTime:    nowRFC3339(),
			Status:      status,
			Description: description,
		},
	}
}

// BuildGetEarlyLoansV2ErrorResp returns the V2 GetEarlyLoans response shape
// with no result list, only the error SysResponse populated.
func BuildGetEarlyLoansV2ErrorResp(transID string, status int32, description string) model.GetEarlyLoansV2Resp {
	return model.GetEarlyLoansV2Resp{
		NS1: nsV2,
		SysResponse: model.SysRespStatus{
			TransID:     transID,
			DateTime:    nowRFC3339(),
			Status:      status,
			Description: description,
		},
	}
}

