package handler

import (
	"context"
	"crypto/subtle"
	"fmt"
	"io"
	"net/http"
	"strings"

	"repayment_service/config"
	"repayment_service/internal/common"
	"repayment_service/internal/handler/codec"
	"repayment_service/internal/helper"
	"repayment_service/internal/util"

	"github.com/google/uuid"
	"go.uber.org/zap"
	"google.golang.org/grpc/metadata"
)

// faultClient is the SOAP fault code used for client-side errors.
const faultClient = "soapenv:Client"

// maxBodySize is the maximum SOAP request body size (5 KB).
const maxBodySize = 5 * 1024

// allowedContentTypes lists MIME types accepted by the SOAP endpoints.
var allowedContentTypes = []string{"text/xml", "application/soap+xml", "application/xml"}

// readBody validates Content-Type and reads the request body with a size limit.
// On failure it writes a SOAP fault and returns nil.
func readBody(w http.ResponseWriter, r *http.Request) []byte {
	ct := r.Header.Get("Content-Type")
	if ct != "" && !isAllowedContentType(ct) {
		codec.WriteFault(w, uuid.NewString(), faultClient, "Unsupported Content-Type; expected text/xml or application/xml")
		return nil
	}

	r.Body = http.MaxBytesReader(w, r.Body, maxBodySize)
	body, err := io.ReadAll(r.Body)
	if err != nil {
		if err.Error() == "http: request body too large" {
			zap.L().Warn("SOAP request body too large")
			codec.WriteFault(w, uuid.NewString(), faultClient, "Request body too large")
		} else {
			zap.L().Error("Failed to read SOAP request", zap.String("ErrMsg", err.Error()))
			codec.WriteFault(w, uuid.NewString(), faultClient, "Error transforming the soap request to be processed")
		}
		return nil
	}
	return body
}

// isAllowedContentType checks whether ct (which may have params like charset)
// starts with one of the accepted MIME types.
func isAllowedContentType(ct string) bool {
	ct = strings.ToLower(strings.TrimSpace(ct))
	for _, allowed := range allowedContentTypes {
		if strings.HasPrefix(ct, allowed) {
			return true
		}
	}
	return false
}

// authCheck validates HTTP Basic Auth against the configured credentials using
// a constant-time comparison to avoid timing attacks.
func authCheck(r *http.Request, cfg *config.Config) bool {
	username, pass, ok := r.BasicAuth()
	if !ok {
		return false
	}
	password, userExists := cfg.Auth.Authentications[username]
	return userExists && subtle.ConstantTimeCompare([]byte(pass), []byte(password)) == 1
}

// withGrpcMetadata enriches the request context with gRPC incoming metadata
// (authorization + correlation ID) so usecases can reuse the same helpers
// (util.GetClientID / util.GetCorrelationID) they rely on for the gRPC path.
// The correlation ID is set by CorrelationIDMiddleware on the request header.
func withGrpcMetadata(r *http.Request) context.Context {
	pairs := make([]string, 0, 4)
	if auth := r.Header.Get("Authorization"); auth != "" {
		pairs = append(pairs, "authorization", auth)
	}
	if cid := r.Header.Get(common.CorrelationIDKey); cid != "" {
		pairs = append(pairs, common.CorrelationIDKey, cid)
	} else {
		pairs = append(pairs, common.CorrelationIDKey, util.GenTransID())
	}
	if len(pairs) == 0 {
		return r.Context()
	}
	return metadata.NewIncomingContext(r.Context(), metadata.Pairs(pairs...))
}

// serveWSDL serves the given WSDL file when authenticated, otherwise 401.
func serveWSDL(w http.ResponseWriter, r *http.Request, authOK bool, path string) {
	if !authOK {
		w.Header().Set("WWW-Authenticate", `Basic realm="restricted"`)
		http.Error(w, "Unauthorized", http.StatusUnauthorized)
		return
	}
	http.ServeFile(w, r, path)
}

// validateOrFaultOp runs ValidateAll on a pb request; on failure it writes the
// operation's success-shape envelope with no data and the error in SysResponse,
// using the supplied builder. Returns false on validation failure.
//
// This keeps fault responses parseable by callers using the same SOAP element
// type as the success path. Use this for post-routing business errors.
// Pre-routing transport errors (auth, malformed XML, etc.) still use WriteFault.
func validateOrFaultOp[T any](
	w http.ResponseWriter,
	transID string,
	validator interface{ ValidateAll() error },
	build func(transID string, code int32, description string) T,
) bool {
	if err := validator.ValidateAll(); err != nil {
		errStr := helper.SplitErrorMessages(err.Error())
		code := util.ConvertStrToInt32(string(common.ReasonGeneralError.Code()))
		codec.WriteResponse(w, build(transID, code, strings.Join(errStr, "|")))
		return false
	}
	return true
}

// businessErrorCode is the sys Code/Status emitted when a usecase returns an
// error (matches the gRPC API layer convention: ReasonErrorWhenCalled = 2).
func businessErrorCode() int32 {
	return util.ConvertStrToInt32(string(common.ReasonErrorWhenCalled.Code()))
}

// logSoapResponse emits a consistent success log line for SOAP operations.
func logSoapResponse(operation, transID string, code int32, description string) {
	zap.L().Info("SOAP Response success",
		zap.String("Operation", operation),
		zap.String("TransID", transID),
		zap.String("Result"+operation, fmt.Sprintf("Code: %v, Description: %v", code, description)),
	)
}

