package model

import "encoding/xml"

// ==================== V1 request envelope ====================

// EnvelopeReqV1 is the SOAP request envelope for /soap/repayment-service.
// Each operation field is a pointer so the decoded value is non-nil only for
// the root element actually present in the request body. This is how the
// handler routes to the correct usecase.
type EnvelopeReqV1 struct {
	XMLName xml.Name `xml:"Envelope"`
	Body    struct {
		GetContractInfo *GetContractInfoReq `xml:"GetContractInfo"`
		Payment         *PaymentReq         `xml:"Payment"`
		GetEarlyLoans   *GetEarlyLoansReq   `xml:"GetEarlyLoans"`
	} `xml:"Body"`
}

// SysRequest captures every possible child of the SOAP <SysRequest> element.
// Different V1 operations populate different subsets (PartnerID/IPAddress for
// GetContractInfo & Payment, RequestorID for GetEarlyLoans); absent fields stay empty.
type SysRequest struct {
	PartnerID   string `xml:"PartnerID"`
	TransID     string `xml:"TransID"`
	IPAddress   string `xml:"IPAddress"`
	RequestorID string `xml:"RequestorID"`
	DateTime    string `xml:"DateTime"`
}

// GetContractInfoReq maps the V1 <GetContractInfo> request element.
type GetContractInfoReq struct {
	SysRequest SysRequest `xml:"SysRequest"`
	ContractNo string     `xml:"ContractNo"`
}

// GetEarlyLoansReq maps the V1 <GetEarlyLoans> request element.
type GetEarlyLoansReq struct {
	SysRequest SysRequest `xml:"SysRequest"`
	ContractNo string     `xml:"ContractNo"`
}

// PaymentReq maps the V1 <Payment> request element.
type PaymentReq struct {
	SysRequest         SysRequest `xml:"SysRequest"`
	TransIDRef         string     `xml:"TransIDRef"`
	ContractNo         string     `xml:"ContractNo"`
	IDCardNumber       string     `xml:"IDCardNumber"`
	CustomerName       string     `xml:"CustomerName"`
	CompanyName        string     `xml:"CompanyName"`
	AmountOverdue      float64    `xml:"AmountOverdue"`
	PayeePhone         string     `xml:"PayeePhone"`
	PaymentBy          string     `xml:"PaymentBy"`
	Relationship       string     `xml:"Relationship"`
	InstallmentDueDate string     `xml:"InstallmentDueDate"`
	MinAmount          float64    `xml:"MinAmount"`
	PaymentDueDate     string     `xml:"PaymentDueDate"`
	RefNo              string     `xml:"RefNo"`
	IdentifyInfo       string     `xml:"IdentifyInfo"`
	PaidAmount         float64    `xml:"PaidAmount"`
	TransTime          string     `xml:"TransTime"`
	NationalID         string     `xml:"NationalID"`
}

// ==================== V2 request envelope ====================

// EnvelopeReqV2 is the SOAP request envelope for /soap/repayment-service-v2.
// Routing works the same way as V1: only the matching operation pointer is set.
type EnvelopeReqV2 struct {
	XMLName xml.Name `xml:"Envelope"`
	Body    struct {
		GetContractByNID *GetContractByNIDReq `xml:"GetContractbyNID"`
		GetEarlyLoans    *GetEarlyLoansV2Req  `xml:"GetEarlyLoans"`
	} `xml:"Body"`
}

// SysRequestV2 captures the V2 <SysRequest> element (SysRequestType).
type SysRequestV2 struct {
	TransID     string `xml:"TransID"`
	RequestorID string `xml:"RequestorID"`
	DateTime    string `xml:"DateTime"`
}

// GetContractByNIDReq maps the V2 <GetContractbyNID> request element.
type GetContractByNIDReq struct {
	SysRequest SysRequestV2 `xml:"SysRequest"`
	NationalID string       `xml:"NationalID"`
}

// GetEarlyLoansV2Req maps the V2 <GetEarlyLoans> request element.
type GetEarlyLoansV2Req struct {
	SysRequest SysRequestV2 `xml:"SysRequest"`
	NationalID string       `xml:"NationalID"`
}

