package model

import "encoding/xml"

const (
	// nsSoapEnv is the SOAP 1.1 envelope namespace.
	nsSoapEnv = "http://schemas.xmlsoap.org/soap/envelope/"
)

// EnvelopeResp is a generic SOAP response envelope. Content holds the concrete
// operation response struct (which carries its own namespaced root element name),
// so a single envelope type serves every operation on both endpoints.
type EnvelopeResp struct {
	XMLName xml.Name `xml:"soapenv:Envelope"`
	Soapenv string   `xml:"xmlns:soapenv,attr"`
	Body    BodyResp `xml:"soapenv:Body"`
}

// BodyResp wraps the operation response element.
type BodyResp struct {
	Content interface{}
}

// NewEnvelope wraps an operation response in a SOAP envelope.
func NewEnvelope(content interface{}) EnvelopeResp {
	return EnvelopeResp{
		Soapenv: nsSoapEnv,
		Body:    BodyResp{Content: content},
	}
}

// ==================== Shared Sys response elements ====================

// SysRespCode is the <SysResponse> element variant that carries a numeric <Code>
// (used by V1 GetContractInfo and Payment).
type SysRespCode struct {
	TransID     string `xml:"TransID"`
	DateTime    string `xml:"DateTime"`
	Code        int32  `xml:"Code"`
	Description string `xml:"Description"`
}

// SysRespStatus is the <SysResponse> element variant that carries a <Status>
// (used by V1 GetEarlyLoans and all V2 operations).
type SysRespStatus struct {
	TransID     string `xml:"TransID"`
	DateTime    string `xml:"DateTime"`
	Status      int32  `xml:"Status"`
	Description string `xml:"Description"`
}

// ==================== V1 response elements ====================

// GetContractInfoResp is the V1 <GetContractInfoResponse> element.
type GetContractInfoResp struct {
	XMLName            xml.Name    `xml:"NS1:GetContractInfoResponse"`
	NS1                string      `xml:"xmlns:NS1,attr"`
	SysResponse        SysRespCode `xml:"SysResponse"`
	ContractNo         *string     `xml:"ContractNo,omitempty"`
	IDCardNumber       *string     `xml:"IDCardNumber,omitempty"`
	CustomerName       *string     `xml:"CustomerName,omitempty"`
	CompanyName        *string     `xml:"CompanyName,omitempty"`
	AmountOverdue      *int64      `xml:"AmountOverdue,omitempty"`
	InstallmentDueDate *string     `xml:"InstallmentDueDate,omitempty"`
	MinAmount          *int64      `xml:"MinAmount,omitempty"`
	PaymentDueDate     *string     `xml:"PaymentDueDate,omitempty"`
}

// PaymentResp is the V1 <PaymentResponse> element.
type PaymentResp struct {
	XMLName     xml.Name    `xml:"NS1:PaymentResponse"`
	NS1         string      `xml:"xmlns:NS1,attr"`
	SysResponse SysRespCode `xml:"SysResponse"`
}

// GetEarlyLoansResp is the V1 <GetEarlyLoansResponse> element.
type GetEarlyLoansResp struct {
	XMLName     xml.Name      `xml:"NS1:GetEarlyLoansResponse"`
	NS1         string        `xml:"xmlns:NS1,attr"`
	SysResponse SysRespStatus `xml:"SysResponse"`
	POItem      *EarlyLoan    `xml:"POItem,omitempty"`
}

// EarlyLoan is a single early repayment PO item (shared shape between V1 and V2).
type EarlyLoan struct {
	PONumber    *string `xml:"PONumber,omitempty"`
	Duedate     *string `xml:"Duedate,omitempty"`
	Money       *string `xml:"Money,omitempty"`
	ContractNum *string `xml:"ContractNum,omitempty"`
	Note        *string `xml:"Note,omitempty"`
}

// ==================== V2 response elements ====================

// GetContractByNIDResp is the V2 <GetContractbyNIDResponse> element.
type GetContractByNIDResp struct {
	XMLName      xml.Name       `xml:"NS1:GetContractbyNIDResponse"`
	NS1          string         `xml:"xmlns:NS1,attr"`
	SysResponse  SysRespStatus  `xml:"SysResponse"`
	ContractInfo []ContractInfo `xml:"ContractInfo,omitempty"`
}

// ContractInfo is a single contract entry in the V2 GetContractbyNID response.
type ContractInfo struct {
	NationalID         string `xml:"NationalID"`
	ContractNO         string `xml:"ContractNO"`
	InstallmentDueDate string `xml:"InstallmentDueDate"`
	PaymentDueDate     string `xml:"PaymentDueDate"`
	AmountOverdue      string `xml:"AmountOverdue"`
	PaymentMindue      string `xml:"PaymentMindue"`
	CompanyName        string `xml:"CompanyName"`
}

// GetEarlyLoansV2Resp is the V2 <GetEarlyLoansResponse> element.
type GetEarlyLoansV2Resp struct {
	XMLName             xml.Name          `xml:"NS1:GetEarlyLoansResponse"`
	NS1                 string            `xml:"xmlns:NS1,attr"`
	SysResponse         SysRespStatus     `xml:"SysResponse"`
	GetEarlyLoansResult *ArrayOfEarlyLoan `xml:"GetEarlyLoansResult,omitempty"`
}

// ArrayOfEarlyLoan wraps the list of early repayment PO items for V2.
type ArrayOfEarlyLoan struct {
	POItem []EarlyLoan `xml:"POItem"`
}

// ==================== SOAP Fault ====================

// EnvelopeFault is a standard SOAP 1.1 fault envelope used for transport-level
// errors (auth, malformed XML, unknown root element, request validation).
type EnvelopeFault struct {
	XMLName xml.Name  `xml:"soapenv:Envelope"`
	Soapenv string    `xml:"xmlns:soapenv,attr"`
	Body    FaultBody `xml:"soapenv:Body"`
}

// FaultBody wraps the SOAP fault element.
type FaultBody struct {
	Fault Fault `xml:"soapenv:Fault"`
}

// Fault is the SOAP fault detail.
type Fault struct {
	Faultcode   string      `xml:"faultcode"`
	Faultstring string      `xml:"faultstring"`
	Detail      FaultDetail `xml:"detail"`
}

// FaultDetail carries the transaction ID for traceability.
type FaultDetail struct {
	TransID string `xml:"TransID"`
}

// NewFault constructs a SOAP fault envelope.
func NewFault(transID, code, description string) EnvelopeFault {
	return EnvelopeFault{
		Soapenv: nsSoapEnv,
		Body: FaultBody{
			Fault: Fault{
				Faultcode:   code,
				Faultstring: description,
				Detail:      FaultDetail{TransID: transID},
			},
		},
	}
}

