// TestV1_PropagatesClientID verifies that the SOAP context carries gRPC incoming
// metadata so usecases can resolve the client ID (derived from Basic Auth) the
// same way they do on the gRPC path.
func TestV1_PropagatesClientID(t *testing.T) {
	var gotClientID string
	uc := &mockUsecase{
		getEarlyLoansFn: func(ctx context.Context, req *dto.GetEarlyLoansRequestDTO) (*dto.GetEarlyLoansResponseDTO, error) {
