			}, nil
		},
	}
	h := NewRepaymentServiceV1SoapHandler(uc, testCfg())

	body := `<soapenv:Envelope xmlns:soapenv="http://schemas.xmlsoap.org/soap/envelope/" xmlns:rep="http://RepaymentService">
		<soapenv:Body>
			<rep:GetEarlyLoans>
				<SysRequest>
					<TransID>` + validUUID + `</TransID>
					<RequestorID>ESB</RequestorID>
					<DateTime>2026-06-01T00:00:00Z</DateTime>
				</SysRequest>
				<ContractNo>C1</ContractNo>
			</rep:GetEarlyLoans>
		</soapenv:Body>
	</soapenv:Envelope>`

	w := httptest.NewRecorder()
	r := httptest.NewRequest(http.MethodPost, "/soap/repayment-service", strings.NewReader(body))
	r.SetBasicAuth("ESB", "1234")
	h.ServeHTTP(w, r)

	if w.Code != http.StatusOK {
