package handler

import (
	"context"
	"net/http"
	"time"

	"repayment_service/config"
	"repayment_service/internal/common"
	"repayment_service/internal/handler/codec"
	"repayment_service/internal/handler/model"
	"repayment_service/internal/usecase"

	"github.com/google/uuid"
	"go.elastic.co/apm/v2"
	"go.uber.org/zap"
)

// RepaymentServiceV1SoapHandler serves SOAP requests at /soap/repayment-service.
// It routes by XML root element to GetContractInfo, Payment, or GetEarlyLoans.
type RepaymentServiceV1SoapHandler struct {
	usecase usecase.IRepaymentServiceUsecase
	cfg     *config.Config
}

// NewRepaymentServiceV1SoapHandler creates the V1 SOAP handler.
func NewRepaymentServiceV1SoapHandler(uc usecase.IRepaymentServiceUsecase, cfg *config.Config) *RepaymentServiceV1SoapHandler {
	return &RepaymentServiceV1SoapHandler{usecase: uc, cfg: cfg}
}

func (h *RepaymentServiceV1SoapHandler) ServeHTTP(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost && r.Method != http.MethodGet {
		codec.WriteFault(w, uuid.NewString(), string(common.ReasonGeneralError.Code()), "Invalid method request")
		return
	}

	authOK := authCheck(r, h.cfg)

	// WSDL discovery: GET ?wsdl
	if _, ok := r.URL.Query()["wsdl"]; ok && r.Method == http.MethodGet {
		serveWSDL(w, r, authOK, h.cfg.Soap.WsdlPathV1)
		return
	}
	if r.Method == http.MethodGet {
		codec.WriteFault(w, uuid.NewString(), faultClient, "Service required POST request")
		return
	}

	if !authOK {
		codec.WriteFault(w, uuid.NewString(), faultClient, "Unauthorization")
		return
	}

	body := readBody(w, r)
	if body == nil {
		return
	}

	env, err := codec.DecodeV1(body)
	if err != nil {
		zap.L().Error("Failed to parse SOAP XML", zap.String("ErrMsg", err.Error()))
		codec.WriteFault(w, uuid.NewString(), faultClient, "Error transforming the soap request to be processed")
		return
	}

	ctx := withGrpcMetadata(r)
	switch {
	case env.Body.GetContractInfo != nil:
		h.handleGetContractInfo(ctx, w, env.Body.GetContractInfo)
	case env.Body.Payment != nil:
		h.handlePayment(ctx, w, env.Body.Payment)
	case env.Body.GetEarlyLoans != nil:
		h.handleGetEarlyLoans(ctx, w, env.Body.GetEarlyLoans)
	default:
		codec.WriteFault(w, uuid.NewString(), faultClient, "Unknown or missing SOAP operation")
	}
}

func (h *RepaymentServiceV1SoapHandler) handleGetContractInfo(ctx context.Context, w http.ResponseWriter, req *model.GetContractInfoReq) {
	span, ctx := apm.StartSpan(ctx, "repaymentService.soap.GetContractInfo", "api")
	defer span.End()
	transID := req.SysRequest.TransID
	span.Context.SetLabel("TransID", transID)

	if !validateOrFaultOp(w, transID, codec.GetContractInfoToPb(req), codec.BuildGetContractInfoErrorResp) {
		return
	}

	reqDTO := codec.GetContractInfoToDTO(req)
	zap.L().Info("Receive request",
		zap.Any("RequestGetContractInfo", reqDTO),
		zap.String("TransID", transID),
		zap.String("Operation", "GetContractInfo"),
	)

	resDTO, err := h.usecase.GetContractInfo(ctx, reqDTO)
	if err != nil {
		apm.CaptureError(ctx, err).Send()
		zap.L().Error("SOAP GetContractInfo failed",
			zap.String("TransID", transID),
			zap.String("ContractNo", req.ContractNo),
			zap.String("ErrMsg", err.Error()),
		)
		codec.WriteErrorResponse(w, codec.BuildGetContractInfoErrorResp(transID, businessErrorCode(), common.ReasonErrorWhenCalled.Message()+err.Error()))
		return
	}

	logSoapResponse("GetContractInfo", transID, int32(resDTO.Sys.Code), resDTO.Sys.Description)
	codec.WriteResponse(w, codec.BuildGetContractInfoResp(resDTO))
}

func (h *RepaymentServiceV1SoapHandler) handlePayment(ctx context.Context, w http.ResponseWriter, req *model.PaymentReq) {
	span, ctx := apm.StartSpan(ctx, "repaymentService.soap.Payment", "api")
	defer span.End()
	transID := req.SysRequest.TransID
	span.Context.SetLabel("TransID", transID)

	if !validateOrFaultOp(w, transID, codec.PaymentToPb(req), codec.BuildPaymentErrorResp) {
		return
	}

	reqDTO := codec.PaymentToDTO(req)
	zap.L().Info("Receive request",
		zap.Any("RequestPayment", reqDTO),
		zap.String("TransID", transID),
		zap.String("Operation", "Payment"),
	)

	resDTO, err := h.usecase.Payment(ctx, reqDTO)
	if err != nil {
		apm.CaptureError(ctx, err).Send()
		zap.L().Error("SOAP Payment failed",
			zap.String("TransID", transID),
			zap.String("ContractNo", req.ContractNo),
			zap.String("ErrMsg", err.Error()),
		)
		codec.WriteErrorResponse(w, codec.BuildPaymentErrorResp(transID, businessErrorCode(), common.ReasonErrorWhenCalled.Message()+err.Error()))
		return
	}

	logSoapResponse("Payment", transID, int32(resDTO.Sys.Code), resDTO.Sys.Description)
	codec.WriteResponse(w, codec.BuildPaymentResp(resDTO))
}

func (h *RepaymentServiceV1SoapHandler) handleGetEarlyLoans(ctx context.Context, w http.ResponseWriter, req *model.GetEarlyLoansReq) {
	span, ctx := apm.StartSpan(ctx, "repaymentService.soap.GetEarlyLoans", "api")
	defer span.End()
	transID := req.SysRequest.TransID
	span.Context.SetLabel("TransID", transID)

	if !validateOrFaultOp(w, transID, codec.GetEarlyLoansToPb(req), codec.BuildGetEarlyLoansErrorResp) {
		return
	}

	reqDTO := codec.GetEarlyLoansToDTO(req)
	zap.L().Info("Receive request",
		zap.Any("RequestGetEarlyLoans", reqDTO),
		zap.String("TransID", transID),
		zap.String("Operation", "GetEarlyLoans"),
	)

	resDTO, err := h.usecase.GetEarlyLoans(ctx, reqDTO)
	if err != nil {
		apm.CaptureError(ctx, err).Send()
		zap.L().Error("SOAP GetEarlyLoans failed",
			zap.String("TransID", transID),
			zap.String("ContractNo", req.ContractNo),
			zap.String("ErrMsg", err.Error()),
		)
		codec.WriteErrorResponse(w, codec.BuildGetEarlyLoansErrorResp(transID, businessErrorCode(), common.ReasonErrorWhenCalled.Message()+err.Error()))
		return
	}
	resDTO.Sys.DateTime = time.Now().Format(time.RFC3339Nano)

	logSoapResponse("GetEarlyLoans", transID, int32(resDTO.Sys.Code), resDTO.Sys.Description)
	codec.WriteResponse(w, codec.BuildGetEarlyLoansResp(resDTO))
}

