package helper

import (
	"repayment_service/internal/dto"
	pb "repayment_service/pb"
)

// V1PbConverter provides explicit conversion between V1 pb and dto types.
type V1PbConverter struct{}

func NewV1PbConverter() *V1PbConverter {
	return &V1PbConverter{}
}

// ==================== GetContractInfo ====================

// GetContractInfoReqFromPb converts pb request to dto.
func (c *V1PbConverter) GetContractInfoReqFromPb(req *pb.GetContractInfoRequest) *dto.GetContractInfoRequestDTO {
	return &dto.GetContractInfoRequestDTO{
		Sys: dto.SysReqNormDTO{
			TransID:     req.GetSys().GetTransID(),
			RequestorID: req.GetSys().GetRequestorID(),
			DateTime:    req.GetSys().GetDateTime(),
		},
		ContractNo: req.GetContractNo(),
	}
}

// GetContractInfoRespToPb converts dto response to pb.
func (c *V1PbConverter) GetContractInfoRespToPb(resDTO *dto.GetContractInfoResponseDTO) *pb.GetContractInfoResponse {
	resp := &pb.GetContractInfoResponse{
		Sys: &pb.SysResp{
			TransID:     resDTO.Sys.TransID,
			DateTime:    resDTO.Sys.DateTime,
			Code:        int32(resDTO.Sys.Code),
			Description: resDTO.Sys.Description,
		},
	}

	if resDTO.ContractNo != nil {
		resp.ContractNo = resDTO.ContractNo
	}
	if resDTO.IDCardNumber != nil {
		resp.IdCardNumber = resDTO.IDCardNumber
	}
	if resDTO.CustomerName != nil {
		resp.CustomerName = resDTO.CustomerName
	}
