			DateTime:    req.GetSys().GetDateTime(),
		},
		NationalID: req.GetNationalID(),
	}
}

// GetContractByNIDRespToPb converts dto response to pb.
func (c *V2PbConverter) GetContractByNIDRespToPb(resDTO *dto.GetContractByNIDResponseDTO) *pb.GetContractByNIDResponse {
	resp := &pb.GetContractByNIDResponse{
		SysResponse: &pb.SysResp{
			TransID:     resDTO.Sys.TransID,
			DateTime:    resDTO.Sys.DateTime,
			Code:        int32(resDTO.Sys.Code),
			Description: resDTO.Sys.Description,
		},
	}

	if len(resDTO.ContractInfo) > 0 {
		pbContracts := make([]*pb.ContractInfoV2, 0, len(resDTO.ContractInfo))
		for _, ci := range resDTO.ContractInfo {
			pbContracts = append(pbContracts, &pb.ContractInfoV2{
				NationalID:         ci.NationalID,
				ContractNo:         ci.ContractNo,
				InstallmentDueDate: ci.InstallmentDueDate,
				PaymentDueDate:     ci.PaymentDueDate,
				AmountOverdue:      ci.AmountOverdue,
				PaymentMindue:      ci.PaymentMindue,
				CompanyName:        ci.CompanyName,
			})
		}
		resp.ContractInfo = pbContracts
	}

	return resp
}

// ==================== GetEarlyLoansV2 ====================

// GetEarlyLoansV2ReqFromPb converts pb request to dto.
func (c *V2PbConverter) GetEarlyLoansV2ReqFromPb(req *pb.GetEarlyLoansV2Request) *dto.GetEarlyLoansV2RequestDTO {
	return &dto.GetEarlyLoansV2RequestDTO{
		Sys: dto.SysReqNormDTO{
			TransID:     req.GetSys().GetTransID(),
			RequestorID: req.GetSys().GetRequestorID(),
			DateTime:    req.GetSys().GetDateTime(),
		},
		NationalID: req.GetNationalID(),
	}
}

// GetEarlyLoansV2RespToPb converts dto response to pb.
func (c *V2PbConverter) GetEarlyLoansV2RespToPb(resDTO *dto.GetEarlyLoansV2ResponseDTO) *pb.GetEarlyLoansV2Response {
	resp := &pb.GetEarlyLoansV2Response{
		SysResponse: &pb.SysResp{
			TransID:     resDTO.Sys.TransID,
			DateTime:    resDTO.Sys.DateTime,
			Code:        int32(resDTO.Sys.Code),
			Description: resDTO.Sys.Description,
		},
	}

	if len(resDTO.GetEarlyLoansResult) > 0 {
		pbItems := make([]*pb.EarlyLoanItem, 0, len(resDTO.GetEarlyLoansResult))
		for _, item := range resDTO.GetEarlyLoansResult {
			pbItem := &pb.EarlyLoanItem{}
			if item.PONumber != nil {
				pbItem.PoNumber = item.PONumber
			}
			if item.DueDate != nil {
				pbItem.Duedate = item.DueDate
			}
			if item.Money != nil {
				pbItem.Money = item.Money
			}
			if item.ContractNum != nil {
				pbItem.ContractNum = item.ContractNum
			}
			if item.Note != nil {
				pbItem.Note = item.Note
			}
			pbItems = append(pbItems, pbItem)
		}
		resp.GetEarlyLoansResult = &pb.ArrayOfEarlyLoan{
			PoItem: pbItems,
		}
	}

	return resp
}

