package helper

import (
	"context"
	"encoding/json"
	"net/http"
	"repayment_service/internal/dto"
	"repayment_service/internal/util"
	"time"

	"github.com/grpc-ecosystem/grpc-gateway/v2/runtime"
	"google.golang.org/grpc/codes"
	"google.golang.org/grpc/status"
)

// CustomErrorHandler to return flat error object
func CustomErrorHandler(ctx context.Context, mux *runtime.ServeMux, marshaler runtime.Marshaler, w http.ResponseWriter, r *http.Request, err error) {
	const fallback = `{"error_code": 500, "message": "Internal server error"}`
	s, ok := status.FromError(err)
	if !ok {
		s = status.New(codes.Unknown, err.Error())
	}

	w.Header().Set("Content-Type", "application/json")

	// Fallback for unexpected errors
	w.WriteHeader(runtime.HTTPStatusFromCode(s.Code()))

	if err := json.NewEncoder(w).Encode(map[string]any{
		"sys": dto.SysRespDTO{
			TransID:     util.GenTransID(),
			DateTime:    time.Now().Format(time.RFC3339Nano),
			Code:        int8(codes.Code(2)), //always return code 2 for error response
			Description: s.Message(),
		},
	}); err != nil {
		http.Error(w, fallback, http.StatusInternalServerError)
	}
}

