// SetIDUnaryServerInterceptor represents set id in case TransID nil
func SetIDUnaryServerInterceptor() grpc.UnaryServerInterceptor {
	return func(ctx context.Context, req interface{}, info *grpc.UnaryServerInfo, handler grpc.UnaryHandler) (interface{}, error) {
		value := reflect.ValueOf(req)
		typeOf := reflect.TypeOf(req)
		if typeOf.Kind() != reflect.Ptr {
			return handler(ctx, req)
		}

		trans := value.Elem().FieldByName("TransID")
		/* if trans.Kind() != reflect.String {
			return handler(ctx, req)
		} */
		if trans.String() != "" {
			return handler(ctx, req)
		}
		id := util.GenTransID()
		if trans.CanSet() {
			trans.SetString(id)
		}
		return handler(ctx, req)
	}
}

// ValidationInterceptor represents validation TransID interceptor
func ValidationInterceptor() grpc.UnaryServerInterceptor {
	return func(ctx context.Context, req interface{}, info *grpc.UnaryServerInfo, handler grpc.UnaryHandler) (interface{}, error) {
		value := reflect.ValueOf(req)
		typeOf := reflect.TypeOf(req)

		if typeOf.Kind() != reflect.Ptr {
			return handler(ctx, req)
		}
		elem := value.Elem()
		_, ok := elem.Type().FieldByName("TransID")
		if !ok {
			return nil, status.Errorf(codes.InvalidArgument, "request missing required field: TransID")
		}
		transID := elem.FieldByName("TransID")
		if transID.Kind() != reflect.String {
			return nil, status.Errorf(codes.InvalidArgument, "TransID must be a string")
		}
		transIDStr := transID.String()
		if transIDStr == "" {
			return nil, status.Errorf(codes.InvalidArgument, "TransID must not be empty")
		}
		if len(transIDStr) != 32 {
			return nil, status.Errorf(codes.InvalidArgument, "TransID must have length of 32")
		}
		return handler(ctx, req)
	}
}

