func ExecutionTimeInterceptor() grpc.UnaryServerInterceptor {
	return func(ctx context.Context, req interface{}, info *grpc.UnaryServerInfo, handler grpc.UnaryHandler) (interface{}, error) {
		startTime := time.Now()
		res, err := handler(ctx, req)
		executionTime := time.Since(startTime).Milliseconds()

		value := reflect.ValueOf(res)
		typeOf := reflect.TypeOf(res)
		if typeOf.Kind() != reflect.Ptr {
			return res, err
		}

		exec := value.Elem().FieldByName("ExecutionTime")

		if exec.Kind() != reflect.Float64 {
			return res, err
		}

		if exec.Float() != 0 {
			return res, err
		}

		if exec.CanSet() {
			exec.SetFloat(float64(executionTime))
		}

		return res, err
	}
}

func StreamInterceptor(log *zap.Logger) grpc.StreamServerInterceptor {
	return func(
		srv interface{},
		stream grpc.ServerStream,
		info *grpc.StreamServerInfo,
		handler grpc.StreamHandler,
	) error {
		apmgrpc.NewStreamServerInterceptor()
		log.Info("Received stream request", zap.String("method", info.FullMethod))
		err := handler(srv, stream)
		if err != nil {
			return err
		}

		log.Info("Sent stream response", zap.String("method", info.FullMethod))

		return nil
	}
}

