func AuthenticationUnaryInterceptor(cfg *config.Config) grpc.UnaryServerInterceptor {
	return func(
		ctx context.Context,
		req interface{},
		info *grpc.UnaryServerInfo,
		handler grpc.UnaryHandler,
	) (interface{}, error) {
		typeOf := reflect.TypeOf(req)
		if typeOf.Kind() != reflect.Ptr {
			return handler(ctx, req)
		}

		md, ok := metadata.FromIncomingContext(ctx)
		if !ok {
			return nil, status.Errorf(codes.InvalidArgument, "Invalid Argument")
		}
		authorization := md["authorization"]
		if len(authorization) < 1 {
			return nil, status.Errorf(codes.PermissionDenied, "Permission Denied")
		}
		authorizationArrays := strings.Split(authorization[0], " ")
		if authorizationArrays[0] != "Basic" {
			return nil, status.Newf(codes.Unauthenticated, "Unauthenticated").Err()
		}
		usernameAndPassword, err := base64.StdEncoding.DecodeString(authorizationArrays[1])
		if err != nil {
			return nil, status.Newf(codes.Unauthenticated, "Unauthenticated").Err()
		}
		usernameAndPasswordArrays := strings.Split(string(usernameAndPassword), ":")
		if len(usernameAndPasswordArrays) != 2 {
			return nil, status.Newf(codes.Unauthenticated, "Unauthenticated").Err()
		}

		if password, ok := cfg.Auth.Authentications[strings.ToLower(usernameAndPasswordArrays[0])]; ok {
			if usernameAndPasswordArrays[1] != password {
				return nil, status.Newf(codes.Unauthenticated, "Unauthenticated").Err()
			}
		}
		// Continue processing the request
		return handler(ctx, req)
	}
}

// CustomValidatorInterceptor call validator as grpc interceptor
func CustomValidatorInterceptor() grpc.UnaryServerInterceptor {
	return func(ctx context.Context, req interface{}, info *grpc.UnaryServerInfo, handler grpc.UnaryHandler) (interface{}, error) {
		if validator, ok := req.(interface{ ValidateAll() error }); ok {
			if err := validator.ValidateAll(); err != nil {
				errStr := splitErrorMessages(err.Error())
				return nil, status.Newf(codes.InvalidArgument, "%v", errStr).Err()
			}
		}
		return handler(ctx, req)
	}
}

// SplitErrorMessages exposes splitErrorMessages for use outside the gRPC
// interceptor (e.g. the SOAP handler validation path).
func SplitErrorMessages(errorStr string) []string {
	return splitErrorMessages(errorStr)
}

// SplitErrorMessages capture "FieldName: message"
func splitErrorMessages(errorStr string) []string {
	// Split error string to parts
	parts := strings.Split(errorStr, "; ")
	var messages []string

	// loop parts splited
	for index, part := range parts {
		// finnding ":" then split
		colonIndex := strings.Index(part, ": ")
		if colonIndex != -1 {
			//Capture field error
			fieldPart := strings.TrimSpace(part[:colonIndex])
			//capture error
			message := strings.TrimSpace(part[colonIndex+2:])
			//capture field error
			dotParts := strings.Split(fieldPart, ".")
			if len(dotParts) > 0 {
				fieldName := dotParts[len(dotParts)-1]
				// Join field and errors
				if message != "" {
					if index < len(parts)-1 {
						messages = append(messages, fieldName+": "+message+", ")
					} else {
						messages = append(messages, fieldName+": "+message)
					}
				}
			}
		}
	}

	return messages
}

// TransIDResponseInterceptor extracts TransID from the request Sys field
// and attaches it to the gRPC response header. Works for all V1 and V2 endpoints.
func TransIDResponseInterceptor() grpc.UnaryServerInterceptor {
	return func(ctx context.Context, req interface{}, info *grpc.UnaryServerInfo, handler grpc.UnaryHandler) (interface{}, error) {
		var transID string

		// Try V1 requests (SysReq)
		if r, ok := req.(interface{ GetSys() *pb.SysReq }); ok {
			if sys := r.GetSys(); sys != nil {
				transID = sys.GetTransID()
			}
		}
		// Try V1 Payment request (SysPaymentReq)
		if transID == "" {
			if r, ok := req.(interface{ GetSys() *pb.SysPaymentReq }); ok {
				if sys := r.GetSys(); sys != nil {
					transID = sys.GetTransID()
				}
			}
		}

		// Set TransID in response header
		if transID != "" {
			_ = grpc.SetHeader(ctx, metadata.Pairs(common.TransIDHeaderKey, transID))
		}

		return handler(ctx, req)
	}
}

// UnaryServerInterceptor to extract and log correlation ID on the gRPC server
func CorrelationIDInterceptor() grpc.UnaryServerInterceptor {
	return func(
		ctx context.Context,
		req interface{},
		info *grpc.UnaryServerInfo,
		handler grpc.UnaryHandler,
	) (interface{}, error) {
		if _, ok := req.(*pb.PaymentRequest); ok {
			// Extract correlation ID from incoming metadata
			var correlationID string
			if md, ok := metadata.FromIncomingContext(ctx); ok {
				if values := md.Get(common.CorrelationIDKey); len(values) > 0 {
					correlationID = values[0]
				} else {
					correlationID = util.GenTransID()
				}
			}

			// Log or use the correlation ID (e.g., for tracing or logging)
			zap.L().Info("Request receive new correlationID", zap.String("CorrelationID", correlationID))

			// Add correlationID to response for capture purpose, BU will take log to BO ticket with log correlationID
			if correlationID != "" {
				_ = grpc.SetHeader(ctx, metadata.Pairs(common.CorrelationIDKey, correlationID))
			}
		}

		// Proceed with the gRPC handler
		return handler(ctx, req)
	}
}

// HTTP Middleware to inject correlation ID into gRPC metadata
func CorrelationIDMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		// Extract or generate a correlation ID
		correlationID := r.Header.Get(common.CorrelationIDKey)
		if correlationID == "" {
			// Generate a new UUID if no correlation ID is provided
			correlationID = util.GenTransID()
		}

		// Add correlation ID to the request header for downstream services
		r.Header.Set(common.CorrelationIDKey, correlationID)

		// Create gRPC metadata and inject the correlation ID
		ctx := r.Context()
		ctx = metadata.AppendToOutgoingContext(ctx, common.CorrelationIDKey, correlationID)

		// Update the request with the new context
		r = r.WithContext(ctx)

		// Call the next handler
		next.ServeHTTP(w, r)
	})
}

