package helper

import (
	"context"
	"repayment_service/config"
	"repayment_service/internal/common"
	"repayment_service/internal/repository"
	"repayment_service/internal/repository/model"
	"time"

	"github.com/bytedance/sonic"
	"go.uber.org/zap"
)

// TransactionLogger handles audit logging to IIB_PAYMENT_TRANSACTION_LOG.
type TransactionLogger struct {
	repo repository.IRepaymentRepository
	cfg  *config.Config
}

// NewTransactionLogger creates a new TransactionLogger.
func NewTransactionLogger(repo repository.IRepaymentRepository, cfg *config.Config) *TransactionLogger {
	return &TransactionLogger{repo: repo, cfg: cfg}
}

// LogSuccess writes a success transaction log entry asynchronously.
func (l *TransactionLogger) LogSuccess(transID, requestorID, transType string, req, resp any) {
	msgStruct := struct {
		Request  any
		Response any
	}{Request: req, Response: resp}

	jsonMsg, err := sonic.Marshal(msgStruct)
	if err != nil {
		logMarshalError(transID, req, resp, err)
		return
	}

	ctx, cancel := context.WithTimeout(context.Background(), 20*time.Second)
	defer cancel()

	l.repo.InsertPaymentTransactionLog(ctx, &model.ProcessLogTrans{
		SchemaName: l.cfg.ServiceParams.AppWsSchema,
		TransID:    transID,
		PartnerID:  requestorID,
		TransType:  transType,
		TransMsg:   string(jsonMsg),
	})
}

// LogError writes an error transaction log entry asynchronously.
func (l *TransactionLogger) LogError(transID, requestorID string, req any, errStr string, currentPayload any) {
	msgStruct := struct {
		Request        any
		Error          string
		CurrentPayload any
	}{Request: req, Error: errStr, CurrentPayload: currentPayload}

	jsonMsg, err := sonic.Marshal(msgStruct)
	if err != nil {
		logMarshalError(transID, req, currentPayload, err)
		return
	}

	ctx, cancel := context.WithTimeout(context.Background(), 20*time.Second)
	defer cancel()

	l.repo.InsertPaymentTransactionLog(ctx, &model.ProcessLogTrans{
		SchemaName: l.cfg.ServiceParams.AppWsSchema,
		TransID:    transID,
		PartnerID:  requestorID,
		TransType:  common.TRANS_TYPE_GetContractInfo,
		TransMsg:   string(jsonMsg),
	})
}

// logMarshalError logs when JSON marshaling fails, using ToString interface if available.
func logMarshalError(transID string, objects ...any) {
	for _, obj := range objects {
		if obj == nil {
			continue
		}
		if ts, ok := obj.(interface{ ToString(string) string }); ok {
			zap.L().Error(
				"Write transaction log: cannot marshal message",
				zap.String("TransID", transID),
				zap.String("Payload", ts.ToString(transID)),
			)
			return
		}
	}
	zap.L().Error(
		"Write transaction log: cannot marshal message",
		zap.String("TransID", transID),
	)
}

