files.internal/repository/pool_executor.go:
package repository

import (
	"context"
	"fmt"
	"time"

	adapter "esb-go-libs/dbadapter"
	adapterDTO "esb-go-libs/dbadapter/dto"
	modelPS "esb-go-libs/dbadapter/model"
	"repayment_service/config"

	"go.elastic.co/apm/v2"
	"go.uber.org/zap"
)

// QueryParam is a convenience alias for pool service query parameters.
type QueryParam = modelPS.QueryParam

// QueryOpts defines the inputs for a pool service query execution.
type QueryOpts struct {
	// SpanName for APM tracing (e.g. "repayment_service.repository.GetPaymentInfoByNationalID")
	SpanName string
	// TransID for logging and tracing
	TransID string
	// Operation name for log context (e.g. "GetContractInfo", "GetContractByNID")
	Operation string
	// QueryString is the SQL or PL/SQL statement
	QueryString string
	// InputParameters are bind variables
	InputParameters []QueryParam
	// OutputParameters for stored procedures (e.g. CURSOR output)
	OutputParameters []QueryParam
	// Username for pool service auth
	Username string
	// Password for pool service auth
	Password string
}

// PoolQueryExecutor encapsulates the repeated pattern of calling a pool service adapter.
// It handles: APM span, context timeout, request construction, error logging, and code-3 (not found) detection.
type PoolQueryExecutor struct {
	cfg *config.Config
}

// NewPoolQueryExecutor creates a new executor.
func NewPoolQueryExecutor(cfg *config.Config) *PoolQueryExecutor {
	return &PoolQueryExecutor{cfg: cfg}
}

// ExecuteResult holds the raw result from a pool service call.
type ExecuteResult struct {
	// ResultsJSON is the raw JSON string from the pool service response.
	ResultsJSON string
}

// Execute runs a query against the pool service adapter.
// Returns nil, nil when data is not found (code 3).
// Returns nil, error on adapter failure or other errors.
func (e *PoolQueryExecutor) Execute(ctx context.Context, poolAdapter adapter.IPoolAPIAdapter, opts QueryOpts) (*ExecuteResult, error) {
	span, ctx := apm.StartSpan(ctx, opts.SpanName, "repository")
	defer span.End()
	span.Context.SetLabel("TransID", opts.TransID)

	// Apply context timeout
	ctx, cancel := context.WithTimeout(ctx, time.Duration(e.cfg.GRPC.ContextTimeout)*time.Second)
	defer cancel()

	// Build pool service request
	req := &modelPS.PoolServiceRequest{
		Sys: modelPS.SysReq{
			TransID:     opts.TransID,
			RequestorID: "repayment-service",
			DateTime:    time.Now().Format(time.RFC3339),
		},
		QueryString:      opts.QueryString,
		InputParameters:  opts.InputParameters,
		OutputParameters: opts.OutputParameters,
	}

	// Call pool service
	result, err := poolAdapter.PoolExecuteQuery(ctx, req, opts.Username, opts.Password)
	if err != nil {
		apm.CaptureError(ctx, err).Send()
		zap.L().Error(
			fmt.Sprintf("Pool service call failed: %s", opts.Operation),
			zap.String("TransID", opts.TransID),
			zap.String("Operation", opts.Operation),
			zap.String("ErrMsg", err.Error()),
		)
		return nil, err
	}

	// Code 3 = data not found
	if result.Sys.Code == 3 {
		zap.L().Info(
			fmt.Sprintf("Pool service data not found: %s", opts.Operation),
			zap.String("TransID", opts.TransID),
			zap.String("Operation", opts.Operation),
		)
		return nil, nil
	}

	return &ExecuteResult{ResultsJSON: result.Results}, nil
}

// ExecuteRaw runs a query and returns the full response DTO (for insert operations that check affected_rows).
func (e *PoolQueryExecutor) ExecuteRaw(ctx context.Context, poolAdapter adapter.IPoolAPIAdapter, opts QueryOpts) (*adapterDTO.ExecuteQueryResponseDTO, error) {
	span, ctx := apm.StartSpan(ctx, opts.SpanName, "repository")
	defer span.End()
	span.Context.SetLabel("TransID", opts.TransID)

	ctx, cancel := context.WithTimeout(ctx, time.Duration(e.cfg.GRPC.ContextTimeout)*time.Second)
	defer cancel()

	req := &modelPS.PoolServiceRequest{
		Sys: modelPS.SysReq{
			TransID:     opts.TransID,
			RequestorID: "repayment-service",
			DateTime:    time.Now().Format(time.RFC3339),
		},
		QueryString:      opts.QueryString,
		InputParameters:  opts.InputParameters,
		OutputParameters: opts.OutputParameters,
	}

	result, err := poolAdapter.PoolExecuteQuery(ctx, req, opts.Username, opts.Password)
	if err != nil {
		apm.CaptureError(ctx, err).Send()
		zap.L().Error(
			fmt.Sprintf("Pool service call failed: %s", opts.Operation),
			zap.String("TransID", opts.TransID),
			zap.String("Operation", opts.Operation),
			zap.String("ErrMsg", err.Error()),
		)
		return nil, err
	}

	return result, nil
}

