package repository

import (
	"context"
	"errors"
	adapter "esb-go-libs/dbadapter"
	modelPS "esb-go-libs/dbadapter/model"
	"fmt"
	"repayment_service/config"
	"repayment_service/internal/repository/model"

	// "repayment_service/internal/adapter"
	// modelPS "repayment_service/internal/adapter/model"
	"strconv"
	"strings"
	"time"

	"github.com/bytedance/sonic"
	"go.elastic.co/apm/v2"

	"go.uber.org/fx"
	"go.uber.org/zap"
)

type (
	IRepaymentRepository interface {
		GetPaymentInfoByContractNo(ctx context.Context, schemaName, transID, contractNo, contractNoAlias string) (pmtInfo *model.PaymentInfo, err error)
		GetPaidDeductOffQueryByContractNbr(ctx context.Context, schemaName, transID, contractNo string, contractNoAlias string) (pmtDeduct *model.PaymentDeduct, err error)
		GetEarlyLoansByContractNo(ctx context.Context, schemaName, transID, contractNo string) (listEarlyLoan []*model.EarlyLoan, err error)
		InsertPaymentConfirm(ctx context.Context, schemaName, transID string, pmtModel *model.IibPaymentConfirmed) (err error)

		//run in goroutine, please log if errors
		InsertPaymentTransactionLog(ctx context.Context, logTrans *model.ProcessLogTrans)

		// V2 - query by NationalID
		GetPaymentInfoByNationalID(ctx context.Context, schemaName, transID, nationalID string) (pmtInfoList []*model.PaymentInfoV2, err error)
		GetPaidDeductByNationalID(ctx context.Context, schemaName, transID, nationalID string) (pmtDeductList []*model.PaidDeductByContract, err error)
		GetEarlyLoansByNationalID(ctx context.Context, schemaName, transID, nationalID string) (listEarlyLoan []*model.EarlyLoan, err error)
		GetPaymentsOfflineByNationalID(ctx context.Context, schemaAppDomino, schemaNameAppWs, transID, nationalID string) (repPaymentList []*model.RepPaymentByContract, err error)
	}

	RepaymentRepositoryImpl struct {
		cfg            *config.Config
		cfAppDbAdapter adapter.IPoolAPIAdapter
		cifDbAdapter   adapter.IPoolAPIAdapter
		executor       *PoolQueryExecutor
	}
)

func NewRepaymentRepository(
	cfg *config.Config,
	params struct {
		fx.In

		CfAppDbAdapter adapter.IPoolAPIAdapter `name:"CfAppDbAdapter"`
		CifDbAdapter   adapter.IPoolAPIAdapter `name:"CifDbAdapter"`
	},
) IRepaymentRepository {
	return &RepaymentRepositoryImpl{
		cfg:            cfg,
		cfAppDbAdapter: params.CfAppDbAdapter,
		cifDbAdapter:   params.CifDbAdapter,
		executor:       NewPoolQueryExecutor(cfg),
	}
}

func (i *RepaymentRepositoryImpl) GetPaymentInfoByContractNo(ctx context.Context, schemaName, transID, contractNo, contractNoAlias string) (paymentInfo *model.PaymentInfo, err error) {
	isWellFormedContractNo := !strings.EqualFold(contractNo, "")

	var queryString string
	if isWellFormedContractNo {
		queryString = fmt.Sprintf(`SELECT ID_NO, CONTRACT_NUMBER, CUST_NAME, AMOUNT_OVERDUE, COMPANY_NAME, INSTALLMENT_DUE_DATE, MIN_AMOUNT_DUE, PAYMENT_DUE_DATE FROM %v.TBL_WS_PAYMENTINFO WHERE CONTRACT_NUMBER = :ContractNumber`, schemaName)
	} else {
		queryString = fmt.Sprintf(`SELECT ID_NO, CONTRACT_NUMBER, CUST_NAME, AMOUNT_OVERDUE, COMPANY_NAME, INSTALLMENT_DUE_DATE, MIN_AMOUNT_DUE, PAYMENT_DUE_DATE FROM %v.TBL_WS_PAYMENTINFO WHERE CONTRACT_NUMBER_ALIAS = :ContractNumber`, schemaName)
	}

	paramValue := contractNo
	if !isWellFormedContractNo {
		paramValue = contractNoAlias
	}

	result, err := i.executor.Execute(ctx, i.cfAppDbAdapter, QueryOpts{
		SpanName:    "repaymentService.repository.GetPaymentInfoByContractNo",
		TransID:     transID,
		Operation:   "GetContractInfo",
		QueryString: queryString,
		InputParameters: []QueryParam{
			{Name: "ContractNumber", Value: paramValue, DataType: "VARCHAR2"},
		},
		Username: i.cfg.CfAppDbClient.Username,
		Password: i.cfg.CfAppDbClient.Password,
	})
	if err != nil {
		return nil, fmt.Errorf("unable to call pool-service")
	}
	if result == nil {
		return nil, nil
	}

	var responseAppWS model.ResponseData
	if err = sonic.UnmarshalString(result.ResultsJSON, &responseAppWS); err != nil {
		zap.L().Error(
			"Failed to unmarshal GetPaymentInfoByContractNo",
			zap.String("TransID", transID),
			zap.String("ErrMsg", err.Error()),
		)
		return nil, fmt.Errorf("unable to unmarshal response from pool-service")
	}

	rawData := responseAppWS.OutParams.Result.Rows[0]
	amountOverdue, _ := strconv.ParseFloat(rawData.AMOUNT_OVERDUE_STR, 64)
	minAmountDue, _ := strconv.ParseFloat(rawData.MIN_AMOUNT_DUE_STR, 64)

	return &model.PaymentInfo{
		ID_NO:                rawData.ID_NO,
		CONTRACT_NUMBER:      rawData.CONTRACT_NUMBER,
		CUST_NAME:            rawData.CUST_NAME,
		AMOUNT_OVERDUE:       amountOverdue,
		COMPANY_NAME:         rawData.COMPANY_NAME,
		INSTALLMENT_DUE_DATE: rawData.INSTALLMENT_DUE_DATE,
		MIN_AMOUNT_DUE:       minAmountDue,
		PAYMENT_DUE_DATE:     rawData.PAYMENT_DUE_DATE,
	}, nil
}

func (i *RepaymentRepositoryImpl) GetPaidDeductOffQueryByContractNbr(ctx context.Context, schemaName, transID, contractNo string, contractNoAlias string) (pmtDeduct *model.PaymentDeduct, err error) {
	paymentDeduct := &model.PaymentDeduct{}
	isWellFormedContractNo := !strings.EqualFold(contractNo, "")

	var queryString string
	if isWellFormedContractNo {
		queryString = fmt.Sprintf("SELECT SUM(PAIDAMOUNT) PAID_DEDUCTION FROM %v.IIB_PAYMENT_CONFIRMED WHERE CONTRACTNO = :1 AND TRUNC(CONFIRMEDDATE) = TRUNC(SYSDATE)", schemaName)
	} else {
		queryString = fmt.Sprintf("SELECT SUM(PAIDAMOUNT) PAID_DEDUCTION FROM %v.IIB_PAYMENT_CONFIRMED WHERE CONTRACT_NUMBER_ALIAS = :1 AND TRUNC(CONFIRMEDDATE) = TRUNC(SYSDATE)", schemaName)
	}

	paramValue := contractNo
	if !isWellFormedContractNo {
		paramValue = contractNoAlias
	}

	result, err := i.executor.Execute(ctx, i.cfAppDbAdapter, QueryOpts{
		SpanName:    "repaymentService.repository.GetPaidDeductOffQueryByContractNbr",
		TransID:     transID,
		Operation:   "GetContractInfo",
		QueryString: queryString,
		InputParameters: []QueryParam{
			{Name: "1", Value: paramValue, DataType: "VARCHAR2"},
		},
		Username: i.cfg.CfAppDbClient.Username,
		Password: i.cfg.CfAppDbClient.Password,
	})
	if err != nil {
		return paymentDeduct, fmt.Errorf("unable to call pool-service")
	}
	if result == nil {
		return paymentDeduct, nil
	}

	var responseFPS model.ResponseDataPaymentDeduct
	if err = sonic.UnmarshalString(result.ResultsJSON, &responseFPS); err != nil {
		zap.L().Error(
			"Failed to unmarshal GetPaidDeductOffQueryByContractNbr",
			zap.String("TransID", transID),
			zap.String("ErrMsg", err.Error()),
		)
		return paymentDeduct, fmt.Errorf("unable to unmarshal response from pool-service")
	}

	if len(responseFPS.OutParams.Result.Rows) > 0 {
		if rawData := responseFPS.OutParams.Result.Rows[0]; rawData.PAID_DEDUCTION != "" {
			paymentDeduct.PAID_DEDUCTION, _ = strconv.ParseFloat(rawData.PAID_DEDUCTION, 64)
		}
	}
	return paymentDeduct, nil
}

func (i *RepaymentRepositoryImpl) GetEarlyLoansByContractNo(ctx context.Context, schemaName, transID, contractNo string) (listEarlyLoan []*model.EarlyLoan, err error) {
	statement := fmt.Sprintf("BEGIN %v.GETEARLYLOANS_REP(:p_contractno, :p_nid, :p_loan);END;", schemaName)

	result, err := i.executor.Execute(ctx, i.cifDbAdapter, QueryOpts{
		SpanName:    "repaymentService.repository.GetEarlyLoansByContractNo",
		TransID:     transID,
		Operation:   "GetEarlyLoans",
		QueryString: statement,
		InputParameters: []QueryParam{
			{Name: "p_contractno", Value: contractNo, DataType: "VARCHAR2"},
			{Name: "p_nid", Value: "", DataType: "VARCHAR2"},
		},
		OutputParameters: []QueryParam{
			{Name: "p_loan", Value: "", DataType: "CURSOR"},
		},
		Username: i.cfg.CifDbClient.Username,
		Password: i.cfg.CifDbClient.Password,
	})
	if err != nil {
		return nil, err
	}
	if result == nil {
		return nil, nil
	}

	var responsePS model.GetEarlyLoansResponsePS
	if err = sonic.UnmarshalString(result.ResultsJSON, &responsePS); err != nil {
		zap.L().Error(
			"Failed to unmarshal GetEarlyLoansByContractNo",
			zap.String("TransID", transID),
			zap.String("ErrMsg", err.Error()),
		)
		return nil, fmt.Errorf("unable to unmarshal response from pool-service")
	}

	if len(responsePS.OutParams.PLoan.Rows) < 1 {
		return nil, nil
	}

	earlyRepaymentData := responsePS.OutParams.PLoan.Rows[0]
	listEarlyLoan = append(listEarlyLoan, &model.EarlyLoan{
		PO_NUMBER: earlyRepaymentData.Ponumber, DUE_DATE: earlyRepaymentData.Duedate,
		MONEY: earlyRepaymentData.Money, CONTRACT_NUM: earlyRepaymentData.Contractnum,
		NOTE: earlyRepaymentData.Note, PCT: earlyRepaymentData.Pct,
	})
	return listEarlyLoan, nil
}

func (i *RepaymentRepositoryImpl) InsertPaymentConfirm(ctx context.Context, schemaName, transID string, pmtModel *model.IibPaymentConfirmed) (err error) {
