// GetPaymentInfoByNationalID retrieves all contract payment info rows for a given national ID.
func (i *RepaymentRepositoryImpl) GetPaymentInfoByNationalID(ctx context.Context, schemaName, transID, nationalID string) (pmtInfoList []*model.PaymentInfoV2, err error) {
	queryString := fmt.Sprintf(`
		SELECT ID_NO, CONTRACT_NUMBER, INSTALLMENT_DUE_DATE, PAYMENT_DUE_DATE, AMOUNT_OVERDUE, MIN_AMOUNT_DUE, COMPANY_NAME 
		FROM %v.TBL_WS_PAYMENTINFO 
		WHERE ID_NO = TRIM(:p_nationalID)
	`, schemaName)

	result, err := i.executor.Execute(ctx, i.cfAppDbAdapter, QueryOpts{
		SpanName:    "repaymentServiceV2.repository.GetPaymentInfoByNationalID",
		TransID:     transID,
		Operation:   "GetContractByNID",
		QueryString: queryString,
		InputParameters: []QueryParam{
			{Name: "p_nationalID", Value: nationalID, DataType: "VARCHAR2"},
		},
		Username: i.cfg.CfAppDbClient.Username,
		Password: i.cfg.CfAppDbClient.Password,
	})
	if err != nil {
		return nil, fmt.Errorf("unable to call pool-service")
	}
	if result == nil {
		return nil, nil
	}

	var responseData model.ResponseDataV2
	if err = sonic.UnmarshalString(result.ResultsJSON, &responseData); err != nil {
		zap.L().Error(
			"Failed to unmarshal GetPaymentInfoByNationalID",
			zap.String("TransID", transID),
			zap.String("ErrMsg", err.Error()),
		)
		return nil, fmt.Errorf("unable to unmarshal response pool-service")
	}

	for _, raw := range responseData.OutParams.Result.Rows {
		pmtInfoList = append(pmtInfoList, &model.PaymentInfoV2{
			ID_NO:                raw.ID_NO,
			CONTRACT_NUMBER:      raw.CONTRACT_NUMBER,
			INSTALLMENT_DUE_DATE: raw.INSTALLMENT_DUE_DATE,
			PAYMENT_DUE_DATE:     raw.PAYMENT_DUE_DATE,
			AMOUNT_OVERDUE:       raw.AMOUNT_OVERDUE_STR,
			MIN_AMOUNT_DUE:       raw.MIN_AMOUNT_DUE_STR,
			COMPANY_NAME:         raw.COMPANY_NAME,
		})
	}
	return pmtInfoList, nil
}

// GetPaidDeductByNationalID retrieves paid deductions grouped by contract number for a given national ID.
func (i *RepaymentRepositoryImpl) GetPaidDeductByNationalID(ctx context.Context, schemaName, transID, nationalID string) (pmtDeductList []*model.PaidDeductByContract, err error) {
	queryString := fmt.Sprintf(`
		SELECT CONTRACTNO, SUM(PAIDAMOUNT) PAID_DEDUCTION 
		FROM %v.IIB_PAYMENT_CONFIRMED 
		WHERE CONTRACTNO IN (SELECT CONTRACT_NUMBER FROM %v.TBL_WS_PAYMENTINFO WHERE ID_NO = :ID_NO)
		AND TRUNC(CONFIRMEDDATE) = TRUNC(SYSDATE) GROUP BY CONTRACTNO
	`, schemaName, schemaName)

	result, err := i.executor.Execute(ctx, i.cfAppDbAdapter, QueryOpts{
		SpanName:    "repaymentServiceV2.repository.GetPaidDeductByNationalID",
		TransID:     transID,
		Operation:   "GetContractByNID",
		QueryString: queryString,
		InputParameters: []QueryParam{
			{Name: "ID_NO", Value: nationalID, DataType: "VARCHAR2"},
		},
		Username: i.cfg.CfAppDbClient.Username,
		Password: i.cfg.CfAppDbClient.Password,
	})
	if err != nil {
		return nil, fmt.Errorf("unable to call pool-service")
	}
	if result == nil {
		return nil, nil
	}

	var responseData model.ResponseDataPaidDeductByNID
	if err = sonic.UnmarshalString(result.ResultsJSON, &responseData); err != nil {
		zap.L().Error(
			"Failed to unmarshal GetPaidDeductByNationalID",
			zap.String("TransID", transID),
			zap.String("ErrMsg", err.Error()),
		)
		return nil, fmt.Errorf("unable to unmarshal response pool-service")
	}

	for _, raw := range responseData.OutParams.Result.Rows {
		paidDeduction := 0.0
		if raw.PAID_DEDUCTION != "" {
