// GetEarlyLoansByNationalID retrieves early loans by national ID via stored procedure.
func (i *RepaymentRepositoryImpl) GetEarlyLoansByNationalID(ctx context.Context, schemaName, transID, nationalID string) (listEarlyLoan []*model.EarlyLoan, err error) {
	statement := fmt.Sprintf("BEGIN %v.GETEARLYLOANS_REP(:p_contractno, :p_nid, :p_loan);END;", schemaName)

	result, err := i.executor.Execute(ctx, i.cifDbAdapter, QueryOpts{
		SpanName:    "repaymentServiceV2.repository.GetEarlyLoansByNationalID",
		TransID:     transID,
		Operation:   "GetEarlyLoansV2",
		QueryString: statement,
		InputParameters: []QueryParam{
			{Name: "p_contractno", Value: "", DataType: "VARCHAR2"},
			{Name: "p_nid", Value: nationalID, DataType: "VARCHAR2"},
		},
		OutputParameters: []QueryParam{
			{Name: "p_loan", Value: "", DataType: "CURSOR"},
		},
		Username: i.cfg.CifDbClient.Username,
		Password: i.cfg.CifDbClient.Password,
	})
	if err != nil {
		return nil, fmt.Errorf("unable to call pool-service")
	}
	if result == nil {
		return nil, nil
	}

	var responsePS model.GetEarlyLoansResponsePS
	if err = sonic.UnmarshalString(result.ResultsJSON, &responsePS); err != nil {
		zap.L().Error(
			"Failed to unmarshal GetEarlyLoansByNationalID",
			zap.String("TransID", transID),
			zap.String("ErrMsg", err.Error()),
		)
		return nil, fmt.Errorf("unable to unmarshal response from pool-service")
	}

	if len(responsePS.OutParams.PLoan.Rows) < 1 {
		return nil, nil
	}

	for _, row := range responsePS.OutParams.PLoan.Rows {
		listEarlyLoan = append(listEarlyLoan, &model.EarlyLoan{
			PO_NUMBER:    row.Ponumber,
			DUE_DATE:     row.Duedate,
			MONEY:        row.Money,
			CONTRACT_NUM: row.Contractnum,
			NOTE:         row.Note,
			PCT:          row.Pct,
		})
	}
	return listEarlyLoan, nil
}

// GetPaymentsOfflineByNationalID retrieves REP_PAYMENTS sums grouped by contract for a given national ID.
func (i *RepaymentRepositoryImpl) GetPaymentsOfflineByNationalID(ctx context.Context, schemaAppDomino, schemaNameAppWs, transID, nationalID string) (repPaymentList []*model.RepPaymentByContract, err error) {
	queryString := fmt.Sprintf(`
		SELECT CONTRACT_NUM, SUM(TRANS_AMOUNT) PAID_DEDUCTION 
		FROM %v.REP_PAYMENTS 
		WHERE CONTRACT_NUM IN (SELECT CONTRACT_NUMBER FROM %v.TBL_WS_PAYMENTINFO WHERE ID_NO = :p_nationalID)
		AND TRUNC(CREATEDATE) = TRUNC(SYSDATE) GROUP BY CONTRACT_NUM
	`, schemaAppDomino, schemaNameAppWs)

	result, err := i.executor.Execute(ctx, i.cfAppDbAdapter, QueryOpts{
		SpanName:    "repaymentServiceV2.repository.GetPaymentsOfflineByNationalID",
		TransID:     transID,
		Operation:   "GetContractByNID",
		QueryString: queryString,
		InputParameters: []QueryParam{
			{Name: "p_nationalID", Value: nationalID, DataType: "VARCHAR2"},
		},
		Username: i.cfg.CfAppDbClient.Username,
		Password: i.cfg.CfAppDbClient.Password,
	})
	if err != nil {
		return nil, fmt.Errorf("unable to call pool-service")
	}
	if result == nil {
		return nil, nil
	}

	var responseData model.ResponseDataRepPaymentByNID
	if err = sonic.UnmarshalString(result.ResultsJSON, &responseData); err != nil {
		zap.L().Error(
			"Failed to unmarshal GetPaymentsOfflineByNationalID",
			zap.String("TransID", transID),
			zap.String("ErrMsg", err.Error()),
		)
		return nil, fmt.Errorf("unable to unmarshal response from pool-service")
	}

	for _, raw := range responseData.OutParams.Result.Rows {
		paidDeduction := 0.0
		if raw.PAID_DEDUCTION != "" {
			paidDeduction, _ = strconv.ParseFloat(raw.PAID_DEDUCTION, 64)
		}
		repPaymentList = append(repPaymentList, &model.RepPaymentByContract{
			CONTRACT_NUM:   raw.CONTRACT_NUM,
			PAID_DEDUCTION: paidDeduction,
		})
	}
	return repPaymentList, nil
}

