package usecase

import (
	"context"
	"errors"
	"esb-go-libs/activemq"
	"esb-go-libs/activemq/domain"
	"fmt"
	"math"
	"regexp"
	"repayment_service/config"
	"repayment_service/internal/adapter"
	adaptermodel "repayment_service/internal/adapter/model"
	"repayment_service/internal/common"
	"repayment_service/internal/dto"
	"repayment_service/internal/helper"
	"repayment_service/internal/repository"
	"repayment_service/internal/repository/model"
	"repayment_service/internal/util"
	"strconv"
	"strings"
	"time"

	"go.elastic.co/apm/v2"
	"go.uber.org/zap"
	"golang.org/x/sync/errgroup"
)

const HttpCodeHeader = "X-Http-Code"

type (
	IRepaymentServiceUsecase interface {
		GetContractInfo(ctx context.Context, req *dto.GetContractInfoRequestDTO) (resDTO *dto.GetContractInfoResponseDTO, err error)
		GetEarlyLoans(ctx context.Context, req *dto.GetEarlyLoansRequestDTO) (resDTO *dto.GetEarlyLoansResponseDTO, err error)
		Payment(ctx context.Context, req *dto.PaymentRequestDTO) (resDTO *dto.PaymentResponseDTO, err error)

		// V2 - query by NationalID
		GetContractByNID(ctx context.Context, req *dto.GetContractByNIDRequestDTO) (resDTO *dto.GetContractByNIDResponseDTO, err error)
		GetEarlyLoansV2(ctx context.Context, req *dto.GetEarlyLoansV2RequestDTO) (resDTO *dto.GetEarlyLoansV2ResponseDTO, err error)
	}

	RepaymentServiceUsecaseImpl struct {
		cfg                        *config.Config
		repaymentServiceRepository repository.IRepaymentRepository
		msgSender                  *activemq.Sender
		txLogger                   *helper.TransactionLogger
		w4Adapter                  adapter.IW4RepaymentAdapter
	}
)

func NewRepaymentServiceUsecase(
	cfg *config.Config,
	repaymentServiceRepository repository.IRepaymentRepository,
	msgSender *activemq.Sender,
	txLogger *helper.TransactionLogger,
	w4Adapter adapter.IW4RepaymentAdapter,
) IRepaymentServiceUsecase {
	return &RepaymentServiceUsecaseImpl{
		cfg:                        cfg,
		repaymentServiceRepository: repaymentServiceRepository,
		msgSender:                  msgSender,
		txLogger:                   txLogger,
		w4Adapter:                  w4Adapter,
	}
}

func (u *RepaymentServiceUsecaseImpl) GetContractInfo(ctx context.Context, req *dto.GetContractInfoRequestDTO) (resDTO *dto.GetContractInfoResponseDTO, err error) {
	var (
		paymentInfo   = &model.PaymentInfo{}
		paidDeduction = &model.PaymentDeduct{}
		isCard        = strings.HasPrefix(req.ContractNo, "1500")

		amtOverdue float64
		minAmtDue  float64
	)
	span, ctx := apm.StartSpan(ctx, "repaymentService.usecase.GetContractInfo", "usecase")
	defer span.End()

	span.Context.SetLabel("TransID", req.Sys.TransID)

	//prepare calling usecase
	var (
		contractNo      string
		contractNoAlias string
	)

	// check if cards, call w4
	if isCard {
		w4Resp, w4Err := u.w4Adapter.GetContractInfoByContractNo(ctx, req.Sys.TransID, req.ContractNo)
		if w4Err != nil {
			apm.CaptureError(ctx, w4Err).Send()

			// write log to table IIB_PAYMENT_TRANSACTION_LOG
			go u.txLogger.LogError(
				req.Sys.TransID,
				req.Sys.RequestorID,
				req,
				w4Err.Error(),
				req,
			)

			zap.L().Error(
				"Failed to call W4 GetContractInfoByContractNo",
				zap.String("TransID", req.Sys.TransID),
				zap.String("ContractNo", req.ContractNo),
				zap.String("Operation", "GetContractInfo"),
				zap.String("ErrMsg", w4Err.Error()),
			)
			return nil, errors.New("failed to call service W4/repayment")
		}

		resDTO = u.buildContractInfoRespFromW4(req.Sys.TransID, w4Resp)

		//write log to log table
		go u.txLogger.LogSuccess(
			req.Sys.TransID,
			req.Sys.RequestorID,
			common.TRANS_TYPE_GetContractInfo,
			req,
			resDTO,
		)

		return resDTO, nil
	}

	if strings.ContainsAny(req.ContractNo, "-") {
		//case formal contractNumber or card
		contractNo = req.ContractNo
	} else {
		//case using contactNoAlias
		contractNoAlias = req.ContractNo
	}

	zap.L().Debug(
		"Getting GetContractInfo with ContractNumber",
		zap.String("TransID", req.Sys.TransID),
		zap.String("Operation", "GetContractInfo"),
		zap.String("ContractNumber", contractNo),
		zap.String("ContractNumberAlias", contractNoAlias),
	)

	//calling repo
	paymentInfo, err = u.repaymentServiceRepository.GetPaymentInfoByContractNo(ctx, u.cfg.ServiceParams.AppWsSchema, req.Sys.TransID, contractNo, contractNoAlias)
	if err != nil {
		apm.CaptureError(ctx, err).Send()

		//write log to table IIB_PAYMENT_TRANSACTION_LOG
		go u.txLogger.LogError(
			req.Sys.TransID,
			req.Sys.RequestorID,
			req,
			err.Error(),
			req,
		)

		zap.L().Error(
			"Failed to call repository",
			zap.String("TransID", req.Sys.TransID),
			zap.String("ContractNo", req.ContractNo),
			zap.String("Operation", "GetContractInfo"),
			zap.String("ErrMsg", err.Error()),
		)
		return nil, errors.New(common.ReasonDBError.Message())
	}

	//case no data payment found for contractNumber/customer has no loan/card loan
	if paymentInfo == nil {
		resDTO = &dto.GetContractInfoResponseDTO{
			Sys: dto.SysRespDTO{
				TransID:     req.Sys.TransID,
				DateTime:    time.Now().Format(time.RFC3339),
				Code:        4,
				Description: "Data not found",
			},
		}

		//write log to table IIB_PAYMENT_TRANSACTION_LOG
		go u.txLogger.LogSuccess(
			req.Sys.TransID,
			req.Sys.RequestorID,
			common.TRANS_TYPE_GetContractInfo,
			req,
			resDTO,
		)

		return resDTO, nil
	}

	//get PAID_DEDUCTION from IIB_PAYMENT_CONFIRMED
	paidDeduction, err = u.repaymentServiceRepository.GetPaidDeductOffQueryByContractNbr(
		ctx,
		u.cfg.ServiceParams.AppWsSchema,
		req.Sys.TransID,
		contractNo,
		contractNoAlias,
	)
	if err != nil {
		//write log to table IIB_PAYMENT_TRANSACTION_LOG
		go u.txLogger.LogError(
			req.Sys.TransID,
			req.Sys.RequestorID,
			req,
			err.Error(),
			req,
		)

		return nil, errors.New(common.ReasonDBError.Message())
	}

	paid := paidDeduction.PAID_DEDUCTION
	//calculate amount overdue
	amtOverdue = paymentInfo.AMOUNT_OVERDUE
	//is customer paid per amount overdue?
	if paid > 0.0 {
		amtOverdue = amtOverdue - paid
	}
	if amtOverdue < 0 {
		amtOverdue = 0
	}

	//calc min amount due
	minAmtDue = paymentInfo.MIN_AMOUNT_DUE
	if isCard && paid > 0.0 {
		minAmtDue = minAmtDue - paidDeduction.PAID_DEDUCTION
	}

	if minAmtDue < 0 {
		minAmtDue = 0
	}

	//try parse installmentDueDate to date
	installmentDueDate := util.SafeParseStringToDate(paymentInfo.INSTALLMENT_DUE_DATE)

	//try parse paymentDueDate to date
	paymentDueDate := util.SafeParseStringToDate(paymentInfo.PAYMENT_DUE_DATE)

	idCardNum := "***" + paymentInfo.ID_NO[len(paymentInfo.ID_NO)-4:]
	//preapre response
	resDTO = &dto.GetContractInfoResponseDTO{
		Sys: dto.SysRespDTO{
			TransID:     req.Sys.TransID,
			DateTime:    time.Now().Format(time.RFC3339),
			Code:        0,
			Description: "OK",
		},
		ContractNo:         &paymentInfo.CONTRACT_NUMBER,
		IDCardNumber:       &idCardNum,
		CustomerName:       &paymentInfo.CUST_NAME,
		CompanyName:        &paymentInfo.COMPANY_NAME,
		AmountOverdue:      &amtOverdue,
		InstallmentDueDate: &installmentDueDate,
		MinAmount:          &minAmtDue,
		PaymentDueDate:     &paymentDueDate,
	}
	//write log to log table
	go u.txLogger.LogSuccess(req.Sys.TransID, req.Sys.RequestorID, common.TRANS_TYPE_GetContractInfo, req, resDTO)

	return resDTO, nil
}

// buildContractInfoRespFromW4 maps a W4 repayment service response to the V1 GetContractInfo response DTO.
// W4 GetContractInfoByContractNo returns a single contract item in the happy case.
// W4 Code: "000" = data found, "100" = data not found.
func (u *RepaymentServiceUsecaseImpl) buildContractInfoRespFromW4(transID string, w4Resp *adaptermodel.EnvelopeW4RepaymentResp) *dto.GetContractInfoResponseDTO {
	// Data not found: W4 returns code 100 (or empty body / no contract items)
	if w4Resp == nil ||
		w4Resp.Code != common.W4_CODE_SUCCESS ||
		len(w4Resp.Data.ContractItems) == 0 {
		return &dto.GetContractInfoResponseDTO{
			Sys: dto.SysRespDTO{
				TransID:     transID,
				DateTime:    time.Now().Format(time.RFC3339),
				Code:        4,
				Description: "Data not found",
			},
		}
	}

	item := w4Resp.Data.ContractItems[0]

	amountOverdue, _ := strconv.ParseFloat(item.AmountOverdue, 64)
	if amountOverdue < 0 {
		amountOverdue = 0
	}
	minAmount, _ := strconv.ParseFloat(item.MinAmount, 64)
	if minAmount < 0 {
		minAmount = 0
	}
	// W4 PaymentDueDate is already in YYYY-MM-DD format, pass through directly
	paymentDueDate := item.PaymentDueDate
	// normalize contractNo from W4
	contractNoNormalized := util.NormalizeCardContractNum(item.ContractNo)

	return &dto.GetContractInfoResponseDTO{
		Sys: dto.SysRespDTO{
			TransID:     transID,
			DateTime:    time.Now().Format(time.RFC3339),
			Code:        0,
			Description: "OK",
		},
		ContractNo:     &contractNoNormalized,
		IDCardNumber:   &item.IDCardNumber,
		CustomerName:   &item.CustomerName,
		CompanyName:    &item.CompanyName,
		AmountOverdue:  &amountOverdue,
		MinAmount:      &minAmount,
		PaymentDueDate: &paymentDueDate,
	}
}

