func (u *RepaymentServiceUsecaseImpl) Payment(ctx context.Context, req *dto.PaymentRequestDTO) (resDTO *dto.PaymentResponseDTO, err error) {
	var correlationID = util.GetCorrelationID(ctx)

	span, _ := apm.StartSpan(ctx, "repaymentService.usecase.Payment", "usecase")
	defer span.End()

	span.Context.SetLabel("TransID", req.Sys.TransID)

	//return immediately like mulesoft
	if req.PaidAmount > 0 && req.PaidAmount < 100000001 {
		//async insert to IIB_PAYMENT_CONFIRMED
		go u.asyncWritePaymentConfirm(correlationID, req)

		//return OK immediately
		resDTO = &dto.PaymentResponseDTO{
			Sys: dto.SysRespDTO{
				TransID:     req.Sys.TransID,
				DateTime:    time.Now().Format(time.RFC3339),
				Code:        common.RESPONSE_OK_CODE,
				Description: common.RESPONSE_OK_DESC,
			},
		}
	} else {
		//return NOT OK
		resDTO = &dto.PaymentResponseDTO{
			Sys: dto.SysRespDTO{
				TransID:     req.Sys.TransID,
				DateTime:    time.Now().Format(time.RFC3339),
				Code:        common.RESPONSE_NOT_OK_CODE,
				Description: common.RESPONSE_NOT_OK_DESC,
			},
		}
	}
	//write log to table
	go u.txLogger.LogSuccess(req.Sys.TransID, req.Sys.PartnerID, common.TRANS_TYPE_Payment, req, resDTO)

	return resDTO, nil
}

func isVPBankAccount(contractNumber string) bool {
	stringAfter := ""
	if _, after, ok := strings.Cut(contractNumber, "_"); ok {
		stringAfter = after
	} else {
		stringAfter = ""
	}
	isNumeric := func(s string) bool {
		matched, _ := regexp.MatchString("^[0-9]*$", s)
		return matched && s != ""
	}
	cond1 := len(contractNumber) < 12 && isNumeric(contractNumber)

	cond2 := len(stringAfter) == 4 && isNumeric(stringAfter)
	return cond1 || cond2
}

func (u *RepaymentServiceUsecaseImpl) asyncWritePaymentConfirm(correlationID string, req *dto.PaymentRequestDTO) {
	var (
		contractNumber = req.ContractNo
		transID        = req.Sys.TransID
	)

	//create new Context
	ctx, cancel := context.WithTimeout(context.Background(), 60*time.Second)
	defer cancel()

	//check if request with contract num alias
	if !(strings.HasPrefix(req.ContractNo, "1500") || strings.Contains(req.ContractNo, "-")) {
		paymentInfo, err := u.repaymentServiceRepository.GetPaymentInfoByContractNo(ctx, u.cfg.ServiceParams.AppWsSchema, req.Sys.TransID, req.ContractNo, req.ContractNo)
		if err != nil {
			zap.L().Error(
				"Failed to call GetPaymentInfoByContractNo",
				zap.String("TransID", transID),
				zap.String("CorrelationID", correlationID),
				zap.String("ContractNo", req.ContractNo),
				zap.String("ErrMsg", err.Error()),
				zap.String("Operation", "Payment"),
			)
			//write request to queue REP.SERVICE.PAYMENT.ERR
			if u.msgSender == nil {
				zap.L().Error("msgSender is nil, cannot send to error queue", zap.String("TransID", transID))
				return
			}
			ctx, cancel := context.WithTimeout(context.Background(), 60*time.Second)
			defer cancel()
			err = u.msgSender.SendMessage(ctx, transID, correlationID, domain.Message{
				Type:    domain.Queue,
				Payload: req.ToArrayByte(transID),
				Headers: map[string]string{
					"trace-id": transID,
				},
				Destination: u.cfg.JMSConfig.PaymentErrQueue.Destination,
			},
				&domain.RetryOption{
					UseRetry:           true,
					InitialInterval:    5,
					MaxIntervalBackOff: 30,
					Multiplier:         2,
					MaxAttemp:          3,
					MaxElapsedTime:     30,
				})
			if err != nil {
				zap.L().Error(
					"Failed to send to error queue REP.SERVICE.PAYMENT.ERR",
					zap.String("TransID", transID),
					zap.String("CorrelationID", correlationID),
					zap.String("ContractNo", req.ContractNo),
					zap.Any("Payload", req),
					zap.String("ErrMsg", err.Error()),
					zap.String("Operation", "Payment"),
				)
			}

			return
		}
		// find well-formed contractNumber
		if paymentInfo == nil {
			zap.L().Error(
				"GetPaymentInfoByContractNo returned nil for alias",
				zap.String("TransID", transID),
				zap.String("CorrelationID", correlationID),
				zap.String("ContractNo", req.ContractNo),
				zap.String("Operation", "Payment"),
			)
			return
		}
		contractNumber = paymentInfo.CONTRACT_NUMBER
	}

	// insert to IIB_PAYMENT_CONFIRMED
	// detect where payment from
	contractFrom := "FEC"
	// contract from
	if req.Sys.PartnerID == "VNP_GW01" && isVPBankAccount(req.ContractNo) {
		contractFrom = "VPB"
	}

	// insert IIB_PAYMENT_CONFIRMED
	err := u.repaymentServiceRepository.InsertPaymentConfirm(ctx, u.cfg.ServiceParams.AppWsSchema, transID, &model.IibPaymentConfirmed{
		TransID:             req.Sys.TransID,
		IpAddress:           req.Sys.IPAddress,
		DateTime:            req.Sys.DateTime,
		TransID_Ref:         req.TransIDRef,
		ContractNo:          contractNumber,
		IDCardNumber:        req.IDCardNumber,
		CustomerName:        req.CustomerName,
		CompanyName:         req.CompanyName,
		AmountOverDue:       req.AmountOverdue,
		RefNo:               req.RefNo,
		IdentifyInfo:        req.IdentifyInfo,
		PaidAmount:          req.PaidAmount,
		TransTime:           req.Sys.DateTime,
		UserName:            req.Sys.PartnerID,
		ContractFrom:        contractFrom,
		ContractNumberAlias: strings.ReplaceAll(contractNumber, "-", ""), //replace "-" from contractNumber if existed
	})
	if err != nil {
		zap.L().Error(
			"Error insert payment to IIB_PAYMENT_CONFIRMED",
			zap.String("TransID", transID),
			zap.String("CorrelationID", correlationID),
			zap.String("Operation", "Payment"),
			zap.String("ContractNumber", req.ContractNo),
			zap.String("ErrMsg", err.Error()),
		)

		// write request to queue REP.SERVICE.PAYMENT.ERR
		if u.msgSender == nil {
			zap.L().Error("msgSender is nil, cannot send to error queue", zap.String("TransID", transID))
			return
		}
		ctx, cancel := context.WithTimeout(context.Background(), 60*time.Second)
		defer cancel()
		err = u.msgSender.SendMessage(ctx, transID, correlationID, domain.Message{
			Type:    domain.Queue,
			Payload: req.ToArrayByte(transID),
			Headers: map[string]string{
				"trace-id":     transID,
				"content-type": "application/json",
			},
			Destination: u.cfg.JMSConfig.PaymentErrQueue.Destination,
		},
			&domain.RetryOption{
				UseRetry:           true,
				InitialInterval:    5,
				MaxIntervalBackOff: 30,
				Multiplier:         2,
				MaxAttemp:          3,
				MaxElapsedTime:     30,
			})
		if err != nil {
			zap.L().Error(
				"Insert IIB_PAYMENT_CONFIRMED failed. Failed to send to error queue REP.SERVICE.PAYMENT.ERR",
				zap.String("TransID", transID),
				zap.String("CorrelationID", correlationID),
				zap.String("ContractNo", req.ContractNo),
				zap.Any("Payload", req),
				zap.String("Operation", "Payment"),
				zap.String("ErrMsg", err.Error()),
			)
		}
		return
	}

	// write request to topic LCS.SUPPRESS
	if u.msgSender == nil {
		zap.L().Error("msgSender is nil, cannot send to LCS.SUPPRESS topic", zap.String("TransID", transID))
		return
	}
	msgPayload := req.ToArrayByte(transID)
	err = u.msgSender.SendMessage(ctx, transID, correlationID, domain.Message{
		Type:    domain.Topic,
		Payload: msgPayload,
		Headers: map[string]string{
			"trace-id": transID,
		},
		Destination: u.cfg.JMSConfig.LcsSuppressTopic.Destination,
	},
		&domain.RetryOption{
			UseRetry:           true,
			InitialInterval:    5,
			MaxIntervalBackOff: 30,
			Multiplier:         2,
			MaxAttemp:          3,
			MaxElapsedTime:     30,
		})
	if err != nil {
		zap.L().Error(
			fmt.Sprintf("Insert IIB_PAYMENT_CONFIRMED success. Failed to send to error queue %s", u.cfg.JMSConfig.LcsSuppressTopic.Destination),
			zap.String("TransID", transID),
			zap.String("CorrelationID", correlationID),
			zap.String("ContractNo", req.ContractNo),
			zap.Any("Payload", req),
			zap.String("Operation", "Payment"),
			zap.String("ErrMsg", err.Error()),
		)
		return
	}

	zap.L().Info(
		"Recognize payment success",
		zap.String("TransID", transID),
		zap.String("CorrelationID", correlationID),
		zap.String("ContractNo", req.ContractNo),
		zap.String("Operation", "Payment"),
		zap.String("Amount", strconv.FormatFloat(req.PaidAmount, 'g', 5, 64)),
	)
}

