// GetContractByNID retrieves all contracts for a given national ID, with deduction calculation.
func (u *RepaymentServiceUsecaseImpl) GetContractByNID(ctx context.Context, req *dto.GetContractByNIDRequestDTO) (resDTO *dto.GetContractByNIDResponseDTO, err error) {
	span, ctx := apm.StartSpan(ctx, "repaymentServiceV2.usecase.GetContractByNID", "usecase")
	defer span.End()
	span.Context.SetLabel("TransID", req.Sys.TransID)

	zap.L().Info(
		"Getting GetContractByNID with NationalID",
		zap.String("TransID", req.Sys.TransID),
		zap.String("Operation", "GetContractByNID"),
		zap.String("NationalID", req.NationalID),
	)

	// Step 1: parallel - repo payment info (loans) + W4 service (cards)
	var (
		paymentInfoList []*model.PaymentInfoV2
		w4Resp          *adaptermodel.EnvelopeW4RepaymentResp
	)

	g1, g1Ctx := errgroup.WithContext(ctx)
	g1.Go(func() error {
		var gErr error
		paymentInfoList, gErr = u.repaymentServiceRepository.GetPaymentInfoByNationalID(
			g1Ctx, u.cfg.ServiceParams.AppWsSchema, req.Sys.TransID, req.NationalID,
		)
		return gErr
	})
	g1.Go(func() error {
		var gErr error
		w4Resp, gErr = u.w4Adapter.GetContractInfoByNid(g1Ctx, req.Sys.TransID, req.NationalID)
		return gErr
	})
	if err = g1.Wait(); err != nil {
		apm.CaptureError(ctx, err).Send()
		zap.L().Error(
			"Failed to call GetPaymentInfoByNationalID or W4 GetContractInfoByNid",
			zap.String("TransID", req.Sys.TransID),
			zap.String("NationalID", req.NationalID),
			zap.String("Operation", "GetContractByNID"),
			zap.String("ErrMsg", err.Error()),
		)
		return nil, errors.New(common.ReasonErrorWhenCalled.Message() + err.Error())
	}

	// W4 has usable data?
	w4HasData := w4Resp != nil &&
		w4Resp.Code == common.W4_CODE_SUCCESS &&
		len(w4Resp.Data.ContractItems) > 0

	// filter out all contractNumber in DB start with 1500
	filteredPmt := make([]*model.PaymentInfoV2, 0, len(paymentInfoList))
	for _, pmt := range paymentInfoList {
		if strings.HasPrefix(pmt.CONTRACT_NUMBER, "1500") {
			continue
		}
		filteredPmt = append(filteredPmt, pmt)
	}

	// Both sources empty -> data not found
	if len(filteredPmt) == 0 && !w4HasData {
		resDTO = &dto.GetContractByNIDResponseDTO{
			Sys: dto.SysRespDTO{
				TransID:     req.Sys.TransID,
				DateTime:    time.Now().Format(time.RFC3339),
				Code:        util.ConvertStrToInt8(common.ReasonDataNotFound.Code()),
				Description: common.ReasonDataNotFound.Message(),
			},
		}
		return resDTO, nil
	}

	// output to result of loan in DB first
	contractInfoList := make([]dto.ContractInfoV2DTO, 0, len(filteredPmt))

	// Step 2: process remaining (non-card) repo contracts with deduction subtract logic
	if len(filteredPmt) > 0 {
		var (
			paidDeductList []*model.PaidDeductByContract
			repPaymentList []*model.RepPaymentByContract
		)

		g2, g2Ctx := errgroup.WithContext(ctx)
		g2.Go(func() error {
			var gErr error
			paidDeductList, gErr = u.repaymentServiceRepository.GetPaidDeductByNationalID(
				g2Ctx, u.cfg.ServiceParams.AppWsSchema, req.Sys.TransID, req.NationalID,
			)
			return gErr
		})
		g2.Go(func() error {
			var gErr error
			repPaymentList, gErr = u.repaymentServiceRepository.GetPaymentsOfflineByNationalID(
				g2Ctx, u.cfg.ServiceParams.AppDominoSchema, u.cfg.ServiceParams.AppWsSchema, req.Sys.TransID, req.NationalID,
			)
			return gErr
		})
		if err = g2.Wait(); err != nil {
			apm.CaptureError(ctx, err).Send()
			zap.L().Error(
				"Failed to call deduction repositories",
				zap.String("TransID", req.Sys.TransID),
				zap.String("NationalID", req.NationalID),
				zap.String("Operation", "GetContractByNID"),
				zap.String("ErrMsg", err.Error()),
			)
			return nil, errors.New(common.ReasonDBError.Message())
		}

		// Build deduction lookup maps. Priority: repPaymentList first, then paidDeductList.
		repPaymentMap := make(map[string]float64, len(repPaymentList))
		for _, r := range repPaymentList {
			repPaymentMap[r.CONTRACT_NUM] = r.PAID_DEDUCTION
		}
		// filter out card contracts (prefix 1500) from paid deduction list
		paidDeductMap := make(map[string]float64, len(paidDeductList))
		for _, d := range paidDeductList {
			if strings.HasPrefix(d.CONTRACTNO, "1500") {
				continue
			}
			paidDeductMap[d.CONTRACTNO] = d.PAID_DEDUCTION
		}

		for _, pmt := range filteredPmt {
			contractNo := pmt.CONTRACT_NUMBER

			// Check repPaymentList first, fallback to paidDeductList, else 0
			deductAmount := 0.0
			if v, ok := repPaymentMap[contractNo]; ok {
				deductAmount = v
			} else if v, ok := paidDeductMap[contractNo]; ok {
				deductAmount = v
			}

			// amountOverdue = amountOverdue - deductAmount (ceil, floor at 0)
			amountOverdue := 0.0
			if pmt.AMOUNT_OVERDUE != "" {
				amountOverdue, _ = strconv.ParseFloat(pmt.AMOUNT_OVERDUE, 64)
			}
			amountOverdue = math.Ceil(amountOverdue - deductAmount)
			if amountOverdue < 0 {
				amountOverdue = 0
			}

			// minAmountDue kept as-is (cards already filtered out, no isCard logic)
			minAmountDue := 0.0
			if pmt.MIN_AMOUNT_DUE != "" {
				minAmountDue, _ = strconv.ParseFloat(pmt.MIN_AMOUNT_DUE, 64)
			}
			if minAmountDue < 0 {
				minAmountDue = 0
			}

			installmentDueDate := util.SafeParseStringToDate(pmt.INSTALLMENT_DUE_DATE)
			paymentDueDate := util.SafeParseStringToDate(pmt.PAYMENT_DUE_DATE)

			contractInfoList = append(contractInfoList, dto.ContractInfoV2DTO{
				NationalID:         pmt.ID_NO,
				ContractNo:         contractNo,
				InstallmentDueDate: installmentDueDate,
				PaymentDueDate:     paymentDueDate,
				AmountOverdue:      amountOverdue,
				PaymentMindue:      minAmountDue,
				CompanyName:        pmt.COMPANY_NAME,
			})
		}
	}

	// Append W4 card contracts to the response
	if w4HasData {
		for _, item := range w4Resp.Data.ContractItems {
			amountOverdue, _ := strconv.ParseFloat(item.AmountOverdue, 64)
			if amountOverdue < 0 {
				amountOverdue = 0
			}
			minAmount, _ := strconv.ParseFloat(item.MinAmount, 64)
			if minAmount < 0 {
				minAmount = 0
			}
			// normalize contractNo from W4
			contractNoNormalized := util.NormalizeCardContractNum(item.ContractNo)

			contractInfoList = append(contractInfoList, dto.ContractInfoV2DTO{
				NationalID:     req.NationalID,
				ContractNo:     contractNoNormalized,
				PaymentDueDate: item.PaymentDueDate, // already YYYY-MM-DD
				AmountOverdue:  amountOverdue,
				PaymentMindue:  minAmount,
				CompanyName:    item.CompanyName,
			})
		}
	}

	resDTO = &dto.GetContractByNIDResponseDTO{
		Sys: dto.SysRespDTO{
			TransID:     req.Sys.TransID,
			DateTime:    time.Now().Format(time.RFC3339),
			Code:        util.ConvertStrToInt8(common.ReasonDataFound.Code()),
			Description: common.ReasonDataFound.Message(),
		},
		ContractInfo: contractInfoList,
	}

	return resDTO, nil
}

