			Sys: dto.SysRespDTO{
				TransID:     req.Sys.TransID,
				DateTime:    time.Now().Format(time.RFC3339),
				Code:        util.ConvertStrToInt8(common.ReasonDataNotFound.Code()),
				Description: common.ReasonDataNotFound.Message(),
			},
		}, nil
	}

	// Map all early loans to response array
	earlyLoanItems := make([]dto.EarlyLoanItemDTO, 0, len(listEarlyLoans))
	for i := range listEarlyLoans {
		loan := listEarlyLoans[i]
		earlyLoanItems = append(earlyLoanItems, dto.EarlyLoanItemDTO{
