			DueDate:     &loan.DUE_DATE,
			Money:       &loan.MONEY,
			ContractNum: &loan.CONTRACT_NUM,
			Note:        &loan.NOTE,
		})
	}

	resDTO = &dto.GetEarlyLoansV2ResponseDTO{
		Sys: dto.SysRespDTO{
			TransID:     req.Sys.TransID,
			DateTime:    time.Now().Format(time.RFC3339),
			Code:        util.ConvertStrToInt8(common.ReasonDataFound.Code()),
			Description: common.ReasonDataFound.Message(),
		},
		GetEarlyLoansResult: earlyLoanItems,
	}

	// go u.txLogger.LogSuccess(req.Sys.TransID, req.Sys.RequestorID, common.TRANS_TYPE_GetEarlyLoansV2, req, resDTO)

	return resDTO, nil
}

