// ==================== GetContractInfo Tests ====================

func TestGetContractInfo_Success_Loan(t *testing.T) {
	repo := &mockRepo{
		getPaymentInfoByContractNoFn: func(ctx context.Context, s, tid, c, a string) (*model.PaymentInfo, error) {
			return &model.PaymentInfo{
				ID_NO:                "210139637",
				CONTRACT_NUMBER:      "20160815-500000-0993",
				CUST_NAME:            "NGUYEN VAN A",
				AMOUNT_OVERDUE:       7929000,
				COMPANY_NAME:         "GALAXY",
				INSTALLMENT_DUE_DATE: "2021-09-09T00:00:00Z",
				MIN_AMOUNT_DUE:       500000,
				PAYMENT_DUE_DATE:     "1900-01-01T00:00:00Z",
			}, nil
		},
		getPaidDeductOffQueryByContractNbrFn: func(ctx context.Context, s, tid, c, a string) (*model.PaymentDeduct, error) {
			return &model.PaymentDeduct{PAID_DEDUCTION: 0}, nil
		},
	}
	uc := newTestUsecase(repo)

	res, err := uc.GetContractInfo(context.Background(), &dto.GetContractInfoRequestDTO{
		Sys:        dto.SysReqNormDTO{TransID: "954865f4-ae2a-41cd-bbc9-f1c332b165e8", RequestorID: "ESB"},
		ContractNo: "20160815-500000-0993",
	})
	if err != nil {
		t.Fatalf("expected no error, got %v", err)
	}
	if res == nil {
		t.Fatal("expected non-nil response")
	}
	if res.Sys.Code != 0 {
		t.Errorf("Code: want 0, got %d", res.Sys.Code)
	}
	if res.ContractNo == nil || *res.ContractNo != "20160815-500000-0993" {
		t.Errorf("ContractNo: want 20160815-500000-0993, got %v", res.ContractNo)
	}
	if res.CustomerName == nil || *res.CustomerName != "NGUYEN VAN A" {
		t.Errorf("CustomerName: want NGUYEN VAN A, got %v", res.CustomerName)
	}
	// ID masked: last 4 digits visible
	if res.IDCardNumber == nil || *res.IDCardNumber != "***9637" {
		t.Errorf("IDCardNumber: want ***9637, got %v", res.IDCardNumber)
	}
	// No deduction, amountOverdue stays
	if res.AmountOverdue == nil || *res.AmountOverdue != 7929000 {
		t.Errorf("AmountOverdue: want 7929000, got %v", res.AmountOverdue)
	}
	// Loan type: minAmount stays (no deduction applied for non-card)
	if res.MinAmount == nil || *res.MinAmount != 500000 {
		t.Errorf("MinAmount: want 500000, got %v", res.MinAmount)
	}
}

