func TestGetContractInfo_Card_NormalizesW4ContractNumber(t *testing.T) {
	repo := &mockRepo{}
	w4 := &mockW4Adapter{
		getContractInfoByContractNoFn: func(ctx context.Context, transID, contractNo string) (*adaptermodel.EnvelopeW4RepaymentResp, error) {
			return &adaptermodel.EnvelopeW4RepaymentResp{
				Code:    "000",
				Message: "Successfully",
				Data: adaptermodel.W4RepaymentData{
					ContractItems: []adaptermodel.W4ContractItem{
						{
							// W4 returns 19-char contract number with 000 prefix
							ContractNo:     "0001500123456789012",
							IDCardNumber:   "***6311",
							CustomerName:   "TRAN THI B",
							CompanyName:    "FC",
							AmountOverdue:  "100000",
							MinAmount:      "0",
							PaymentDueDate: "2026-05-09",
						},
					},
				},
			}, nil
		},
	}
	uc := newTestUsecaseWithW4(repo, w4)

	res, err := uc.GetContractInfo(context.Background(), &dto.GetContractInfoRequestDTO{
		Sys:        dto.SysReqNormDTO{TransID: "954865f4-ae2a-41cd-bbc9-f1c332b165e8", RequestorID: "ESB"},
		ContractNo: "1500123456789012",
	})
	if err != nil {
		t.Fatalf("expected no error, got %v", err)
	}
	if res.ContractNo == nil {
		t.Fatal("ContractNo: expected non-nil")
