package util

import (
	"context"
	"encoding/base64"
	"strconv"
	"strings"
	"time"

	"github.com/google/uuid"
	"go.uber.org/zap"
	"google.golang.org/grpc/metadata"
)

const (
	layoutYYYY_MM_DD = "2006-01-02 15:04:05"
	CorrelationIDKey = "x-correlation-id"
)

func GenTransID() string {
	return uuid.New().String()
}

func ConvertStrToInt8(input string) int8 {
	result, err := strconv.ParseInt(input, 10, 8)
	if err == nil {
		return int8(result)
	}
	return 0
}

func ConvertStrToInt32(input string) int32 {
	result, err := strconv.ParseInt(input, 10, 32)
	if err == nil {
		return int32(result)
	}
	return 0
}

func NVL[T comparable](value *T, defaultValue T) T {
	if value == nil {
		return defaultValue
	}
	return *value
}

func GetClientID(ctx context.Context) string {
	if md, ok := metadata.FromIncomingContext(ctx); ok {
		authorization, ok := md["authorization"]
		if !ok {
			return ""
		}
		authorizationArrays := strings.Split(authorization[0], " ")
		if authorizationArrays[0] != "Basic" {
			return ""
		}
		usernameAndPassword, err := base64.StdEncoding.DecodeString(authorizationArrays[1])
		if err != nil {
			return ""
		}
		usernameAndPasswordArrays := strings.Split(string(usernameAndPassword), ":")
		if len(usernameAndPasswordArrays) != 2 {
			return ""
		}
		return usernameAndPasswordArrays[0]
	} else {
		return ""
	}
}

func AddFPSAuth(ctx context.Context, userName, passWord string) context.Context {
	auth := strings.ToLower(userName) + ":" + passWord
	enc := base64.StdEncoding.EncodeToString([]byte(auth))
	mdMap := map[string]string{
		"authorization": "Basic " + enc,
	}

	md := metadata.New(mdMap)
	return metadata.NewOutgoingContext(ctx, md)
}

func SafeParseStringToDate(stringDate string) (resultParse string) {
	resultParse = ""
	if parsed, err := time.Parse(time.RFC3339, stringDate); err == nil {
		resultParse = parsed.Format("2006-01-02")
	}
	return resultParse
}

// format time format  ISO 8601:2025-08-06T10:55:00+07:00 to YYYY-MM-DD HH:mm:ss
func FormatStrDateISO2Resp(input string) string {
	if input == "" {
		return ""
	}
	formattedDate, err := time.Parse(time.RFC3339, input)
	if err != nil {
		zap.L().Warn("Can not convert input to dateTime YYYY-MM-DD HH:mm:ss", zap.String("Input", input))
		return ""
	}
	// Format the time.Time object into yyyy-MM-dd HH:mm:ss format
	return formattedDate.Format(layoutYYYY_MM_DD)
}

func GetCorrelationID(ctx context.Context) string {
	var correlationID string
	// Access correlation ID from context
	if md, ok := metadata.FromIncomingContext(ctx); ok {
		if correlationIDs := md.Get(CorrelationIDKey); len(correlationIDs) > 0 {
			correlationID = correlationIDs[0]
			zap.L().Info("Grabed correlationID, processing request", zap.String("CorrelationID", correlationID))
		}
	}
	return correlationID
}

// strPtrFromFloat64 converts a float64 to a *string.
func StrPtrFromFloat64(v float64) *string {
	s := strconv.FormatFloat(v, 'f', -1, 64)
	return &s
}

// NormalizeCardContractNum cut prefix "000" + contractNumber from response W4
// Ex 000150000XXXXXX -> 150000XXXXXXX
func NormalizeCardContractNum(cardContractNumber string) string {
	result, _ := strings.CutPrefix(cardContractNumber, "000")
	return result
}

