package util

import "testing"

func TestSafeParseStringToDate(t *testing.T) {
	tests := []struct {
		name  string
		input string
		want  string
	}{
		{"UTC Z format", "2021-09-09T00:00:00Z", "2021-09-09"},
		{"timezone +07:00", "2021-09-09T00:00:00+07:00", "2021-09-09"},
		{"with time component", "2022-05-24T10:58:00.062000+07:00", "2022-05-24"},
		{"RFC3339 full", "2025-08-06T10:55:00+07:00", "2025-08-06"},
		{"empty string", "", ""},
		{"invalid format", "09-09-2021", ""},
		{"date only", "2021-09-09", ""},
		{"1900 date", "1900-01-01T00:00:00Z", "1900-01-01"},
	}

	for _, tc := range tests {
		t.Run(tc.name, func(t *testing.T) {
			got := SafeParseStringToDate(tc.input)
			if got != tc.want {
				t.Errorf("SafeParseStringToDate(%q): want %q, got %q", tc.input, tc.want, got)
			}
		})
	}
}

func TestConvertStrToInt8(t *testing.T) {
	tests := []struct {
		name  string
		input string
		want  int8
	}{
		{"valid 1", "1", 1},
		{"valid 3", "3", 3},
		{"negative", "-1", -1},
		{"zero", "0", 0},
		{"empty", "", 0},
		{"non-numeric", "abc", 0},
		{"overflow", "200", 0},
	}

	for _, tc := range tests {
		t.Run(tc.name, func(t *testing.T) {
			got := ConvertStrToInt8(tc.input)
			if got != tc.want {
				t.Errorf("ConvertStrToInt8(%q): want %d, got %d", tc.input, tc.want, got)
			}
		})
	}
}

func TestConvertStrToInt32(t *testing.T) {
	tests := []struct {
		name  string
		input string
		want  int32
	}{
		{"valid", "12345", 12345},
		{"negative", "-100", -100},
		{"zero", "0", 0},
		{"empty", "", 0},
		{"non-numeric", "abc", 0},
	}

	for _, tc := range tests {
		t.Run(tc.name, func(t *testing.T) {
			got := ConvertStrToInt32(tc.input)
			if got != tc.want {
				t.Errorf("ConvertStrToInt32(%q): want %d, got %d", tc.input, tc.want, got)
			}
		})
	}
}

func TestNormalizeCardContractNum(t *testing.T) {
	tests := []struct {
		name  string
		input string
		want  string
	}{
		{
			name:  "strips leading 000 from W4 card contract",
			input: "0001500150000000199",
			want:  "1500150000000199",
		},
		{
			name:  "no prefix returns input unchanged",
			input: "1500150000000199",
			want:  "1500150000000199",
		},
		{
			name:  "strips only one 000 (leaves remainder)",
			input: "000000150000000199",
			want:  "000150000000199",
		},
		{
			name:  "exactly 000 returns empty string",
			input: "000",
			want:  "",
		},
		{
			name:  "empty input returns empty string",
			input: "",
			want:  "",
		},
		{
			name:  "fewer than three leading zeros not stripped",
			input: "00150000",
			want:  "00150000",
		},
		{
			name:  "non-card style with 000 prefix is still stripped (function is purely lexical)",
			input: "00012345",
			want:  "12345",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got := NormalizeCardContractNum(tt.input)
			if got != tt.want {
				t.Errorf("NormalizeCardContractNum(%q) = %q, want %q", tt.input, got, tt.want)
			}
		})
	}
}

