syntax = "proto3";
option go_package = ".;pb";

package pb;

import "protoc-gen-openapiv2/options/annotations.proto";
import "google/api/annotations.proto";
import "repayment_service_message.proto";

option (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_swagger) = {
    info: {
        title: "Repayment service Apis";
        version: "1.1";
    };
    security_definitions: {
        security: {
            key: "APIKeyAuthentication";
            value: {
                type: TYPE_API_KEY;
                in: IN_HEADER;
                name: "Authorization";
            }
        }
    }
};

// RepaymentServiceAPI provides V1 repayment operations using contract number as the primary identifier.
service RepaymentServiceAPI {
    // GetContractInfo retrieves payment information for a loan contract by its contract number.
    rpc GetContractInfo(GetContractInfoRequest) returns (GetContractInfoResponse) {
        option (google.api.http) = {
            post: "/repayment-service/GetContractInfo",
            body: "*"
        };
        option (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_operation) = {
            summary: "Get contract info by ContractNo";
            tags: "Repaymenservice inquiry";
            security: {
                security_requirement: {
                    key: "APIKeyAuthentication";
                    value: {}
                }
            };
        };
    }

    // GetEarlyLoans retrieves early repayment loan details (PO items) by contract number.
    rpc GetEarlyLoans(GetEarlyLoansRequest) returns (GetEarlyLoansResponse) {
        option (google.api.http) = {
            post: "/repayment-service/GetEarlyLoans",
            body: "*"
        };
        option (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_operation) = {
            summary: "Get early loan info by ContractNo";
            tags: "Repaymenservice inquiry";
            security: {
                security_requirement: {
                    key: "APIKeyAuthentication";
                    value: {}
                }
            }
        };
    }

    // Payment submits a loan repayment transaction. Returns immediately; processing is asynchronous.
    rpc Payment(PaymentRequest) returns (PaymentResponse) {
        option (google.api.http) = {
            post: "/repayment-service/Payment"
            body: "*"
        };
        option (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_operation) = {
            summary: "Do payment";
            tags: "Payment";
            security: {
                security_requirement: {
                    key: "APIKeyAuthentication";
                    value: {}
                }
            }
        };
    }
};

// RepaymentServiceV2API provides V2 repayment operations using national ID as the primary identifier.
// Responses may return multiple contracts associated with a single national ID.
service RepaymentServiceV2API {
    // GetContractByNID retrieves all contract payment information associated with a given national ID.
    // Unlike V1, this may return multiple contracts in a single response.
    rpc GetContractByNID(GetContractByNIDRequest) returns (GetContractByNIDResponse) {
        option (google.api.http) = {
            post: "/repayment-service-v2/GetContractbyNID",
            body: "*"
        };
        option (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_operation) = {
            summary: "Get contract info by NationalID";
            tags: "repayment-service-v2";
            security: {
                security_requirement: {
                    key: "APIKeyAuthentication";
                    value: {}
                }
            };
        };
    };

    // GetEarlyLoansV2 retrieves early repayment loan details (PO items) by national ID.
    rpc GetEarlyLoansV2(GetEarlyLoansV2Request) returns (GetEarlyLoansV2Response) {
        option (google.api.http) = {
            post: "/repayment-service-v2/GetEarlyLoans",
            body: "*"
        };
        option (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_operation) = {
            summary: "Get early loan info by NationalID";
            tags: "repayment-service-v2";
            security: {
                security_requirement: {
                    key: "APIKeyAuthentication";
                    value: {}
                }
            };
        };
    };
}

