syntax = "proto3";
option go_package = ".;pb";

package pb;

import "protoc-gen-openapiv2/options/annotations.proto";
import "validate/validate.proto"; //new validator

// GetContractInfoRequest is the request message for GetContractInfo (V1).
message GetContractInfoRequest {
    // System request metadata.
    SysReq sys = 1[
        (validate.rules).message.required = true
    ];
    // The loan contract number or contract number alias.
    string contract_no = 2[
        (validate.rules).string.min_len = 1,
        (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_field) = {
            description: "Contract number, must not be empty"
        }
    ];
}

// GetContractInfoResponse is the response message for GetContractInfo (V1).
// Returns a single contract's payment information.
message GetContractInfoResponse {
    // System response metadata.
    SysResp sys= 1;
    // The loan contract number.
    optional string contract_no = 2;
    // Customer's ID card number (masked, last 4 digits visible).
    optional string id_card_number = 3;
    // Customer's full name.
    optional string customer_name = 4;
    // Invoice company name (e.g. CF, FC, GALAXY).
    optional string company_name = 5;
    // Total overdue amount.
    optional float amount_overdue = 6;
    // Installment due date.
    optional string installment_due_date = 7;
    // Minimum amount due for payment.
    optional float min_amount = 8;
    // Payment due date.
    optional string payment_due_date = 9;
}

// SysReq contains common request metadata sent by the caller.
message SysReq {
    // Unique transaction ID in UUID format.
    string trans_i_d = 1[
        (validate.rules).string = {
            min_len: 1,
            uuid: true
        },
        (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_field) = {
            description: "TransactionID, must be unique and should follow UUID standard"
        }
    ];
    // Identifier of the calling system (e.g. PEGA, ESB).
    string requestor_i_d = 2[
        (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_field) = {
            description: "Caller system ID"
        }
    ];
    // Request timestamp as string.
    string date_time = 3[
        (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_field) = {
            description: "Date time as string"
        }
    ];
}

// SysResp contains common response metadata returned to the caller.
message SysResp {
    // Transaction ID echoed from the request.
    string trans_i_d = 1;
    // Response timestamp.
    string date_time = 2;
    // Status code: 1 = DATA_FOUND, 2 = ERROR_WHEN_CALLED, 3 = DATA_NOT_FOUND.
    int32 code = 3;
    // Human-readable status description.
    string description = 4;
}

// SysPaymentReq contains request metadata specific to payment operations.
message SysPaymentReq {
    // Unique transaction ID in UUID format.
    string trans_i_d = 1[
        (validate.rules).string = {
            min_len: 1,
            uuid: true
        },
        (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_field) = {
            description: "TransactionID, must be unique and should follow UUID standard"
        }
    ];
    // Identifier of the partner system submitting the payment.
    string partner_i_d = 2[
        (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_field) = {
            description: "Partner system ID"
        }
    ];
    // IP address of the requestor.
    string ip_address = 3[
        (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_field) = {
            description: "IP Address of requestor"
        }
    ];
    // Request timestamp as string.
    string date_time = 4[
        (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_field) = {
            description: "Date time as string"
        }
    ];
}

// GetEarlyLoansRequest is the request message for GetEarlyLoans (V1).
message GetEarlyLoansRequest {
    // System request metadata.
    SysReq sys = 1;
    // The loan contract number.
    string contract_no = 2[
        (validate.rules).string.min_len = 1,
        (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_field) = {
            description: "Contract number, must not be empty"
        }
    ];       
}

// GetEarlyLoansResponse is the response message for GetEarlyLoans (V1).
message GetEarlyLoansResponse {
    // POItemType represents a single early repayment purchase order item.
    message POItemType{
        // Purchase order number.
        optional string po_number = 1;
        // Due date for the early repayment.
        optional string duedate = 2;
        // Repayment amount.
        optional string money = 3;
        // Associated contract number.
        optional string contract_num = 4;
        // Additional notes.
        optional string note = 5;
    }
    // System response metadata.
    SysResp sys = 1;
    // Early repayment PO item details.
    optional POItemType po_item = 2;
}

// PaymentRequest is the request message for the Payment RPC.
message PaymentRequest {
    // System request metadata for payment.
    SysPaymentReq sys = 1[
        (validate.rules).message.required = true
    ];
    // Reference to a previous transaction ID (e.g. from GetContractInfo).
    string trans_i_d_ref = 2;
    // The loan contract number.
    string contract_no = 3[
        (validate.rules).string.min_len = 1
    ];
    // Customer's ID card number.
    string id_card_number = 4;
    // Customer's full name.
    string customer_name = 5;
    // Invoice company name (e.g. CF, FC, GALAXY).
    string company_name = 6;
    // Total overdue amount.
    double amount_overdue = 7[
        (validate.rules).double.gte = 0
    ];
    // Phone number of the payee.
    string payee_phone = 8;
    // Payment channel or method.
    string payment_by = 9;
    // Relationship of the payer to the contract holder.
    string relationship = 10;
    // Installment due date.
    string installment_due_date = 11;
    // Minimum amount due for payment.
    double min_amount = 12;
    // Payment due date.
    string payment_due_date = 13;
    // Partner reference number.
    string ref_no = 14;
    // Additional identification information.
    string identify_info = 15;
    // Actual amount paid.
    double paid_amount = 16;
    // Transaction timestamp.
    string trans_time = 17;
    // Customer's national ID.
    string national_i_d = 18;
}

// PaymentResponse is the response message for the Payment RPC.
message PaymentResponse {
    // System response metadata.
    SysResp sys = 1;
}

// ==================== RepaymentServiceV2 Messages ====================

// GetContractByNIDRequest is the request message for GetContractByNID (V2).
// Uses national ID instead of contract number to look up contracts.
message GetContractByNIDRequest {
    // System request metadata.
    SysReq sys = 1 [
        (validate.rules).message.required = true
    ];
    // Customer's national ID.
    string national_i_d = 2 [
        (validate.rules).string.min_len = 1,
        (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_field) = {
            description: "National ID, must not be empty"
        }
    ];
}

// GetContractByNIDResponse is the response message for GetContractByNID (V2).
// May return multiple contracts associated with the given national ID.
message GetContractByNIDResponse {
    // System response metadata.
    SysResp sys_response = 1;
    // List of contracts found for the national ID.
    repeated ContractInfoV2 contract_info = 2;
}

// ContractInfoV2 represents a single contract's payment information in V2 responses.
message ContractInfoV2 {
    // Customer's national ID.
    string national_i_d = 1;
    // The loan contract number.
    string contract_no = 2;
    // Installment due date.
    string installment_due_date = 3;
    // Payment due date.
    string payment_due_date = 4;
    // Total overdue amount.
    double amount_overdue = 5;
    // Minimum amount due for payment.
    double payment_mindue = 6;
    // Invoice company name: CF, FC, or GALAXY.
    string company_name = 7;
}

// GetEarlyLoansV2Request is the request message for GetEarlyLoansV2 (V2).
// Uses national ID instead of contract number.
message GetEarlyLoansV2Request {
    // System request metadata.
    SysReq sys = 1 [
        (validate.rules).message.required = true
    ];
    // Customer's national ID.
    string national_i_d = 2 [
        (validate.rules).string.min_len = 1,
        (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_field) = {
            description: "National ID, must not be empty"
        }
    ];
}

// GetEarlyLoansV2Response is the response message for GetEarlyLoansV2 (V2).
message GetEarlyLoansV2Response {
    // System response metadata.
    SysResp sys_response = 1;
    // Early repayment loan results.
    ArrayOfEarlyLoan get_early_loans_result = 2;
}

// EarlyLoanItem represents a single early repayment purchase order item.
message EarlyLoanItem {
    // Purchase order number.
    optional string po_number = 1;
    // Due date for the early repayment.
    optional string duedate = 2;
    // Repayment amount.
    optional string money = 3;
    // Associated contract number.
    optional string contract_num = 4;
    // Additional notes.
    optional string note = 5;
}

// ArrayOfEarlyLoan is a wrapper for a list of early repayment PO items.
message ArrayOfEarlyLoan {
    // List of early repayment PO items.
    repeated EarlyLoanItem po_item = 1;
}

